const t = (id: string, unitId: string, name: string, description: string, explanation: string, keyPoints: string[], flashcards: {id:string,front:string,back:string}[], questions: {id:string,topicId:string,question:string,options:string[],correctAnswer:number,explanation:string,difficulty:'foundation'|'intermediate'|'higher'|'further'}[]) => ({
  id, unitId, name, description, explanation, keyPoints, flashcards,
  videos: [{ id: `${id}-v1`, title: `${name} - GCSE English`, videoId: 'dQw4w9WgXcQ', channel: 'Mr Bruff' }],
  questions,
});

export const englishSubject: Subject = {
  id: 'english',
  name: 'English',
  icon: '\u{1F4D6}',
  color: '#ec4899',
  examBoard: 'AQA',
  specification: 'GCSE English Language (8700) & Literature (8702)',
  units: [
    {
      id: 'eng-lang1', subjectId: 'english', name: 'English Language Paper 1',
      topics: [
        t('eng-lang1-reading', 'eng-lang1', 'Reading Fiction Extracts', 'Inference, language analysis, structure analysis and critical evaluation of fiction texts.',
          'AQA English Language Paper 1 Section A tests your ability to read and respond to an unseen fiction extract from the 20th or 21st century. The paper consists of four questions worth increasing marks. Question 1 asks you to identify four explicit pieces of information. Question 2 asks you to analyse the effect of language in a specific section, and Question 3 focuses on how the writer has structured the text to interest the reader.\n\nQuestion 4, worth 20 marks, requires you to critically evaluate the text, considering how successfully the writer achieves a particular effect. You must take a clear position and support your argument with evidence from the text. Using short, embedded quotations is essential, and you must comment on the writer\'s methods such as word choice, imagery, sentence structure and narrative perspective.\n\nTo succeed, you should practise identifying language devices (metaphors, similes, personification, pathetic fallacy), analysing structural features (shifts in focus, narrative perspective changes, cyclical structures, foreshadowing) and writing evaluative responses that offer a personal judgement supported by textual evidence.',
          ['Q1 tests information retrieval - find four things from a given section', 'Q2 requires analysis of language effects using subject terminology', 'Q3 focuses on structural choices and shifts across the whole text', 'Q4 is an evaluative response requiring a critical opinion with evidence', 'Always embed short quotations and analyse the effect of specific words'],
          [{id:'ef01',front:'What does AQA Paper 1 Q2 ask you to do?',back:'Analyse the effects of the writer\'s language choices in a specific section of the text, using relevant subject terminology.'},{id:'ef02',front:'What is the difference between language and structure analysis?',back:'Language analysis focuses on word choices and literary devices. Structure analysis examines how the text is organised, including shifts in focus, perspective, and narrative pace.'},{id:'ef03',front:'What is critical evaluation in Q4?',back:'Giving a personal judgement on how effectively the writer achieves a stated aim, supported by textual evidence and analysis of methods.'}],
          [{id:'eng-lr-q1',topicId:'eng-lang1-reading',question:'Which of the following is the best example of analysing language rather than simply identifying it?',options:['The writer uses a metaphor in this paragraph','The writer uses alliteration to create a sense of urgency','The metaphor "sea of troubles" suggests the character feels overwhelmed and unable to cope, conveying a sense of helplessness','The text contains several examples of figurative language'],correctAnswer:2,explanation:'Effective language analysis names the device, quotes it, and explains the effect on the reader. Simply identifying a technique without explaining its impact is feature-spotting.',difficulty:'intermediate'},
           {id:'eng-lr-q2',topicId:'eng-lang1-reading',question:'In Paper 1 Q3, what does "structural analysis" primarily focus on?',options:['The writer\'s use of metaphor and simile','How the text is organised and how the focus shifts','The accuracy of spelling and punctuation','The writer\'s biographical background'],correctAnswer:1,explanation:'Q3 asks about structure: how the writer organises the text, shifts focus between different elements, changes pace, and uses the beginning and ending to shape meaning.',difficulty:'intermediate'},
           {id:'eng-lr-q3',topicId:'eng-lang1-reading',question:'A student writes: "The writer uses the word dark to describe the room." How could this be improved to achieve a higher mark?',options:['Add more quotations from the text','Identify what type of word "dark" is','Explain the connotations of "dark" and how it creates an atmosphere of menace or foreboding for the reader','Write a longer paragraph about the setting'],correctAnswer:2,explanation:'Higher-level responses explore connotations and effects on the reader rather than simply identifying word choices. Explaining how "dark" creates atmosphere demonstrates analytical skill.',difficulty:'higher'},
           {id:'eng-lr-q4',topicId:'eng-lang1-reading',question:'In Paper 1 Q1, how many correct pieces of information must you identify from the text?',options:['Two','Three','Four','Five'],correctAnswer:2,explanation:'Paper 1 Q1 is worth 4 marks and asks you to list four things from a specified section of the text. Each correct piece of explicit information earns one mark.',difficulty:'foundation'},
           {id:'eng-lr-q5',topicId:'eng-lang1-reading',question:'What is "feature-spotting" and why should it be avoided?',options:['Identifying features of the text, which is always rewarded','Naming a technique without analysing its effect, which gains limited marks','Using too many quotations in an answer','Writing about features of the exam paper format'],correctAnswer:1,explanation:'Feature-spotting means identifying a technique (e.g. "the writer uses a simile") without explaining its effect on the reader. It gains minimal marks because analysis requires exploration of meaning and impact.',difficulty:'intermediate'},
           {id:'eng-lr-q6',topicId:'eng-lang1-reading',question:'Which of the following is an example of personification?',options:['"The sun was like a golden coin in the sky"','"The wind whispered secrets through the trees"','"The sky turned from blue to grey"','"He ran as fast as a cheetah"'],correctAnswer:1,explanation:'Personification gives human qualities to non-human things. The wind cannot literally whisper secrets; attributing this human action to nature creates an eerie, mysterious atmosphere.',difficulty:'foundation'},
           {id:'eng-lr-q7',topicId:'eng-lang1-reading',question:'A text begins with a wide, panoramic description of a city, then gradually narrows to focus on one room and one character. What structural technique is this?',options:['Flashback','Zoom-in or narrowing of focus','Cyclical structure','Foreshadowing'],correctAnswer:1,explanation:'A narrowing or zoom-in focus moves from a broad perspective to a specific detail, drawing the reader into the scene. This structural technique creates a sense of intimacy and directs attention to what matters most.',difficulty:'intermediate'},
           {id:'eng-lr-q8',topicId:'eng-lang1-reading',question:'What is a cyclical structure?',options:['A text that gets progressively longer in each paragraph','A text that ends where it began, returning to the same idea, image or setting','A text written entirely in circular sentences','A text that only describes circles or round objects'],correctAnswer:1,explanation:'A cyclical structure returns at the end to the same place, image or idea introduced at the beginning. This creates a sense of completeness, entrapment or inevitability and is a common structural technique in fiction.',difficulty:'intermediate'},
           {id:'eng-lr-q9',topicId:'eng-lang1-reading',question:'For Paper 1 Q4, a student writes: "I totally agree with the statement." What is wrong with this approach?',options:['Nothing - you must always agree','The student should provide a nuanced response, potentially agreeing with parts and questioning others, supported by evidence','You must always disagree with the statement','You should not give your opinion at all'],correctAnswer:1,explanation:'Q4 requires critical evaluation. While you can agree, the strongest responses consider the statement carefully, may partially agree or disagree, and always support their position with specific textual evidence and analysis of methods.',difficulty:'higher'},
           {id:'eng-lr-q10',topicId:'eng-lang1-reading',question:'What does the term "connotation" mean?',options:['The dictionary definition of a word','The implied or associated meaning a word carries beyond its literal definition','A type of punctuation mark','A grammatical error in writing'],correctAnswer:1,explanation:'Connotations are the feelings, ideas or associations that a word suggests beyond its literal meaning. For example, "childlike" has positive connotations of innocence, while "childish" has negative connotations of immaturity.',difficulty:'foundation'},
           {id:'eng-lr-q11',topicId:'eng-lang1-reading',question:'A writer shifts from past tense to present tense midway through a passage. What might this structural choice suggest?',options:['The writer made a grammatical error','The shift creates immediacy, making events feel more vivid and urgent for the reader','Present tense is always better than past tense','It has no particular significance'],correctAnswer:1,explanation:'A deliberate tense shift from past to present creates immediacy and draws the reader into the moment. It can signal a change in the character\'s emotional state or mark a significant turning point in the narrative.',difficulty:'higher'},
           {id:'eng-lr-q12',topicId:'eng-lang1-reading',question:'Which of the following best describes the skill of inference?',options:['Copying information directly from the text','Reading beyond the literal meaning to understand what is implied or suggested','Guessing what happens next in the story','Identifying spelling mistakes in the text'],correctAnswer:1,explanation:'Inference means reading between the lines to understand what a writer implies rather than states directly. It requires you to use clues in the text to draw conclusions about character, mood, theme or atmosphere.',difficulty:'foundation'},
           {id:'eng-lr-q13',topicId:'eng-lang1-reading',question:'A narrator describes another character as having "a smile that never quite reached his eyes." What can be inferred?',options:['The character has an eye condition','The character is genuinely happy','The character\'s friendliness is superficial or insincere','The narrator dislikes describing faces'],correctAnswer:2,explanation:'The phrase suggests a disconnect between the character\'s outward expression and true feelings. A smile that does not reach the eyes implies insincerity, deception, or emotional distance, creating an uneasy atmosphere.',difficulty:'intermediate'},
           {id:'eng-lr-q14',topicId:'eng-lang1-reading',question:'What is the effect of a writer using short, single-sentence paragraphs?',options:['It shows the writer has run out of ideas','It creates dramatic emphasis, forces the reader to pause, and draws attention to a key moment','It is a sign of poor writing','It makes the text easier to skim-read'],correctAnswer:1,explanation:'Short, standalone paragraphs create visual and rhythmic emphasis. The surrounding white space forces the reader to slow down, drawing attention to the isolated idea and often signalling a dramatic or emotional turning point.',difficulty:'intermediate'},
           {id:'eng-lr-q15',topicId:'eng-lang1-reading',question:'An extract ends with the character standing alone in silence after a dramatic event. What structural purpose might this serve?',options:['It means the story has a happy ending','It creates a sense of anticlimax, reflection or isolation, leaving the reader with a lingering emotional impact','It is simply the end of the page','It suggests the character is deaf'],correctAnswer:1,explanation:'Ending on a moment of stillness and silence after drama creates a powerful contrast. It can convey isolation, the weight of consequences, or invite the reader to reflect on the significance of events. This is a deliberate structural choice by the writer.',difficulty:'further'}]),
        t('eng-lang1-writing', 'eng-lang1', 'Descriptive & Narrative Writing', 'Techniques and approaches for creative writing in Paper 1 Section B.',
          'Paper 1 Section B is worth 40 marks (24 for content and organisation, 16 for technical accuracy). You will be given a choice of two tasks: one descriptive and one narrative, often linked to an image stimulus. Planning is essential; spend around 5 minutes organising your ideas before writing.\n\nFor descriptive writing, focus on creating a vivid sensory experience for the reader. Use the five senses, figurative language (similes, metaphors, personification), varied sentence structures, and carefully chosen vocabulary. Zoom in on specific details rather than trying to describe everything. Create atmosphere through pathetic fallacy and show rather than tell emotions.\n\nFor narrative writing, plan a clear structure with a beginning, development, climax, and resolution. Avoid overly complex plots; a focused, small-scale narrative with developed characters is more effective than an action-packed adventure. Use techniques such as in medias res (starting in the middle of the action), cyclical structures, shifts in time, dialogue, and interior monologue to engage the reader. Remember that 16 marks are for SPaG, so accuracy in spelling, punctuation and grammar matters enormously.',
          ['Plan before writing - 5 minutes of planning saves time and improves quality', 'Descriptive writing: use sensory detail and zoom in on specifics', 'Narrative writing: keep the plot focused and develop character', 'Vary sentence structures for effect - short sentences for impact, longer for description', 'Technical accuracy (SPaG) is worth 16 of the 40 marks'],
          [{id:'ef04',front:'What are the marks for Paper 1 Section B?',back:'40 marks total: 24 for content and organisation, 16 for technical accuracy (spelling, punctuation, grammar).'},{id:'ef05',front:'What is "in medias res"?',back:'A narrative technique where the story begins in the middle of the action, then fills in backstory later to hook the reader immediately.'},{id:'ef06',front:'Name three techniques for effective descriptive writing.',back:'Sensory detail (five senses), figurative language (similes, metaphors, personification), and varied sentence structures (short for impact, long for flowing description).'}],
          [{id:'eng-lw-q1',topicId:'eng-lang1-writing',question:'Which opening is most effective for a narrative writing response?',options:['Once upon a time, there was a boy called Jack who lived in a house.','It was a dark and stormy night when everything went wrong.','The door slammed. Silence. Then the slow creak of footsteps on the stairs above.','I am going to write a story about a scary experience I once had.'],correctAnswer:2,explanation:'The third option uses short, dramatic sentences, creates tension through sound, and drops the reader into the middle of the action. It demonstrates varied sentence structures and engages the reader immediately.',difficulty:'intermediate'},
           {id:'eng-lw-q2',topicId:'eng-lang1-writing',question:'What is the most important thing to remember about descriptive writing at GCSE level?',options:['Include as many events as possible to keep the reader interested','Focus on specific details and create atmosphere using sensory language','Use as many long, complex words as possible','Write at least four pages to get full marks'],correctAnswer:1,explanation:'Descriptive writing rewards quality over quantity. Focusing on precise sensory details, creating atmosphere, and using carefully chosen language is far more effective than covering lots of ground superficially.',difficulty:'intermediate'},
           {id:'eng-lw-q3',topicId:'eng-lang1-writing',question:'A student writes: "The forest was scary and dark." Which revision best improves this sentence?',options:['"The forest was very, very scary and really dark."','"Skeletal branches clawed at the leaden sky, while shadows pooled like dark water between the twisted roots."','"The forest was scary, dark, gloomy, foreboding and terrifying."','"I walked into the forest and it was dark."'],correctAnswer:1,explanation:'The improved version uses specific imagery (skeletal branches, leaden sky), figurative language (clawed, pooled like dark water), and shows rather than tells the atmosphere. This demonstrates the craft expected at higher levels.',difficulty:'higher'},
           {id:'eng-lw-q4',topicId:'eng-lang1-writing',question:'What does "show, don\'t tell" mean in creative writing?',options:['Include illustrations with your writing','Describe emotions through actions, sensory detail and imagery rather than simply stating them','Show your plan to the examiner','Tell the reader what happens, then show them a picture'],correctAnswer:1,explanation:'"Show, don\'t tell" means conveying feelings and atmosphere through concrete detail rather than abstract statements. Instead of writing "She was sad", describe her actions: "She pressed her forehead against the cold glass, watching the rain blur the world outside."',difficulty:'foundation'},
           {id:'eng-lw-q5',topicId:'eng-lang1-writing',question:'What is "in medias res"?',options:['A type of sentence structure','Beginning a narrative in the middle of the action','Writing in a foreign language','A technique for ending stories'],correctAnswer:1,explanation:'In medias res means starting a story in the middle of events rather than from the very beginning. This immediately engages the reader by dropping them into the action and creating intrigue about what has already happened.',difficulty:'intermediate'},
           {id:'eng-lw-q6',topicId:'eng-lang1-writing',question:'How much time should you spend planning your Paper 1 creative writing response?',options:['No time - just start writing immediately','Around 5 minutes to organise ideas and structure','At least 20 minutes','The entire exam time should be spent planning'],correctAnswer:1,explanation:'Spending about 5 minutes planning helps you organise your ideas, structure your writing and avoid losing focus midway. A brief plan covering key images, structure and vocabulary choices significantly improves the quality of the final piece.',difficulty:'foundation'},
           {id:'eng-lw-q7',topicId:'eng-lang1-writing',question:'Which of the following is the best use of the five senses in descriptive writing?',options:['"I could see, hear, smell, taste and touch everything around me."','"The acrid tang of smoke caught in my throat; somewhere distant, a siren wailed."','"The place was noisy and smelly."','"I used all five senses to describe the scene."'],correctAnswer:1,explanation:'The second option naturally integrates taste/smell ("acrid tang of smoke caught in my throat") and sound ("a siren wailed") into the description. Effective sensory writing weaves detail naturally rather than listing senses mechanically.',difficulty:'intermediate'},
           {id:'eng-lw-q8',topicId:'eng-lang1-writing',question:'A student writes a narrative with twelve different characters and five location changes. What advice would you give?',options:['Add even more characters for variety','Simplify: focus on fewer characters and a single setting to develop depth','The more events, the better the story','Location changes always improve a narrative'],correctAnswer:1,explanation:'At GCSE, a tightly focused narrative with well-developed characters and a limited setting is far more effective than a sprawling plot. Depth of characterisation and atmospheric detail score higher than quantity of events.',difficulty:'intermediate'},
           {id:'eng-lw-q9',topicId:'eng-lang1-writing',question:'What is pathetic fallacy and how is it used in creative writing?',options:['Writing about feelings of sympathy','Using weather or natural surroundings to reflect the mood or emotions in the scene','A technique for creating humour','Describing characters who are pathetic'],correctAnswer:1,explanation:'Pathetic fallacy uses the natural environment to mirror emotional states. For example, describing torrential rain during a character\'s grief, or bright sunshine during a moment of joy. It creates atmosphere and reinforces mood.',difficulty:'intermediate'},
           {id:'eng-lw-q10',topicId:'eng-lang1-writing',question:'What effect does a one-word sentence have in narrative writing?',options:['It shows a lack of vocabulary','It creates dramatic impact, emphasis or a sudden shift in pace','It is always grammatically incorrect','It wastes space on the page'],correctAnswer:1,explanation:'One-word sentences like "Silence." or "Gone." create powerful dramatic emphasis. They force the reader to pause, highlight a key moment, and create a sharp contrast with surrounding longer sentences.',difficulty:'foundation'},
           {id:'eng-lw-q11',topicId:'eng-lang1-writing',question:'Which narrative perspective is most commonly used in GCSE creative writing?',options:['Second person (you)','Third person omniscient only','First person (I) or third person limited','Only dialogue with no narration'],correctAnswer:2,explanation:'First person creates intimacy and allows direct access to thoughts and feelings. Third person limited offers flexibility while maintaining focus. Both are effective choices for GCSE creative writing.',difficulty:'foundation'},
           {id:'eng-lw-q12',topicId:'eng-lang1-writing',question:'What is a cyclical narrative structure and why might you use it?',options:['A story that goes round in circles with no plot','A narrative that ends by returning to the opening image or situation, creating a sense of completeness','Writing the same paragraph repeatedly','A story about cycling'],correctAnswer:1,explanation:'A cyclical structure returns to the opening image, phrase or situation at the end. This creates a satisfying sense of completeness and can suggest that nothing has changed, or highlight how much has changed through contrast.',difficulty:'higher'},
           {id:'eng-lw-q13',topicId:'eng-lang1-writing',question:'Why is it important to vary paragraph length in creative writing?',options:['All paragraphs should be the same length for consistency','Varied paragraph lengths control pace: short paragraphs quicken pace and create tension, while longer ones slow it for description','Longer paragraphs always get more marks','Paragraph length does not matter at GCSE'],correctAnswer:1,explanation:'Varying paragraph length is a deliberate structural choice that controls pacing. Short paragraphs increase urgency and tension, while longer paragraphs allow for detailed description and reflection. This variety keeps the reader engaged.',difficulty:'intermediate'},
           {id:'eng-lw-q14',topicId:'eng-lang1-writing',question:'A student ends their narrative with: "And then I woke up and it was all a dream." Why is this problematic?',options:['Dreams are interesting to read about','It is a cliche that undermines the story by making all preceding events meaningless, disappointing the reader','It is the best way to end a story','Examiners love dream endings'],correctAnswer:1,explanation:'The "it was all a dream" ending is a well-known cliche that frustrates readers by rendering the entire narrative pointless. It suggests the student could not think of a satisfying resolution. A strong ending should feel earned and meaningful.',difficulty:'higher'},
           {id:'eng-lw-q15',topicId:'eng-lang1-writing',question:'What is the purpose of an extended metaphor in descriptive writing?',options:['To use as many metaphors as possible','To sustain a single metaphorical comparison throughout a passage, creating a cohesive thematic thread','To make writing sound complicated','Extended metaphors are the same as similes'],correctAnswer:1,explanation:'An extended metaphor develops a single comparison across several sentences or an entire passage. For example, comparing a city to a living organism throughout a description creates a unified, sophisticated piece of writing with a strong thematic thread.',difficulty:'further'}]),
      ],
    },
    {
      id: 'eng-lang2', subjectId: 'english', name: 'English Language Paper 2',
      topics: [
        t('eng-lang2-reading', 'eng-lang2', 'Reading Non-Fiction', 'Comparing viewpoints, summarising, and analysing persuasive techniques in non-fiction texts.',
          'AQA English Language Paper 2 Section A presents two linked non-fiction texts from different time periods: one from the 19th century and one from the 20th or 21st century. The four reading questions test different skills. Question 1 requires you to identify true statements from one text. Question 2 asks you to synthesise and summarise differences or similarities between the two texts on a given topic.\n\nQuestion 3 asks you to analyse the writer\'s use of language in one of the texts, just as in Paper 1. Question 4, worth 16 marks, requires you to compare how the two writers convey their different perspectives on a shared theme. You must consider both similarities and differences in their viewpoints and methods.\n\nKey skills for Paper 2 reading include understanding how 19th-century language and conventions differ from modern writing, identifying rhetorical and persuasive techniques (anecdote, direct address, rhetorical questions, statistics, emotive language), and constructing comparative responses that move between texts rather than writing about each separately.',
          ['Q1 tests information retrieval - shade the correct true statements', 'Q2 requires synthesis across both texts with inferences', 'Q3 analyses language effects in one text', 'Q4 compares writers\' viewpoints AND methods across both texts', 'Compare by moving between texts, not writing about them separately'],
          [{id:'ef07',front:'What is synthesis in Paper 2 Q2?',back:'Drawing together information from both texts to identify similarities or differences on a given topic, making inferences rather than just copying.'},{id:'ef08',front:'What does Paper 2 Q4 ask you to compare?',back:'Both the writers\' viewpoints (what they think) and methods (how they convey their ideas) across the two texts.'},{id:'ef09',front:'Name three persuasive techniques used in non-fiction writing.',back:'Rhetorical questions, direct address (using "you"), and emotive language designed to provoke an emotional response in the reader.'}],
          [{id:'eng-nr-q1',topicId:'eng-lang2-reading',question:'In Paper 2 Q4, what is the most effective approach to comparing two writers\' viewpoints?',options:['Write about Text 1 in full, then write about Text 2 in full','Alternate between the texts in each paragraph, making direct comparisons','Only write about the text you understand better','Focus on identifying techniques without comparing viewpoints'],correctAnswer:1,explanation:'The most effective approach is to integrate comparison throughout your response, moving between texts and making explicit links using comparative connectives like "similarly", "however", and "in contrast".',difficulty:'intermediate'},
           {id:'eng-nr-q2',topicId:'eng-lang2-reading',question:'A 19th-century text uses the phrase "the wretched poor." What does this suggest about the writer\'s attitude?',options:['They are indifferent to poverty','They have sympathy for those in poverty, as "wretched" implies pity','They believe poverty is deserved','They are writing a factual report with no opinion'],correctAnswer:1,explanation:'The adjective "wretched" carries connotations of suffering and misery. By choosing this emotive word, the writer reveals a sympathetic attitude towards those living in poverty, inviting the reader to share their compassion.',difficulty:'higher'},
           {id:'eng-nr-q3',topicId:'eng-lang2-reading',question:'Which of the following is a key difference between 19th-century and modern non-fiction texts?',options:['Modern texts are always shorter','19th-century texts often use more formal register, longer sentences and complex vocabulary','19th-century texts never express opinions','Modern texts do not use rhetorical devices'],correctAnswer:1,explanation:'19th-century texts typically employ a more formal register, longer and more complex sentence structures, and elevated vocabulary. Understanding this convention helps you analyse the texts in context.',difficulty:'intermediate'},
           {id:'eng-nr-q4',topicId:'eng-lang2-reading',question:'What does Paper 2 Q1 ask you to do?',options:['Write a summary of both texts','Shade the boxes next to the four true statements about one text','Analyse the writer\'s use of language','Compare the two writers\' viewpoints'],correctAnswer:1,explanation:'Paper 2 Q1 is worth 4 marks and asks you to identify four true statements about one of the texts by shading the correct boxes. It tests basic information retrieval and comprehension.',difficulty:'foundation'},
           {id:'eng-nr-q5',topicId:'eng-lang2-reading',question:'What does "synthesis" mean in the context of Paper 2 Q2?',options:['Creating something artificial','Combining information from both texts to identify similarities or differences on a topic','Analysing language techniques','Writing your own non-fiction text'],correctAnswer:1,explanation:'Synthesis means drawing together material from both texts to show how they connect or differ on a given topic. It requires inference rather than simply copying phrases from each text.',difficulty:'intermediate'},
           {id:'eng-nr-q6',topicId:'eng-lang2-reading',question:'Which of the following is an example of emotive language?',options:['"The report found that 45% of households were affected."','"The innocent children were left to suffer in appalling, inhumane conditions."','"The meeting will take place on Tuesday at 3pm."','"London is the capital city of England."'],correctAnswer:1,explanation:'Emotive language is designed to provoke an emotional response. Words like "innocent", "suffer", "appalling" and "inhumane" are chosen to make the reader feel sympathy and outrage, influencing their attitude towards the issue.',difficulty:'foundation'},
           {id:'eng-nr-q7',topicId:'eng-lang2-reading',question:'A non-fiction writer uses the phrase "We cannot simply stand by." What technique is this?',options:['Statistic','Direct address using inclusive pronoun "we"','Hyperbole','Onomatopoeia'],correctAnswer:1,explanation:'Using "we" is direct address with an inclusive pronoun that creates a sense of shared responsibility between writer and reader. It makes the reader feel personally involved and more likely to agree with the writer\'s position.',difficulty:'intermediate'},
           {id:'eng-nr-q8',topicId:'eng-lang2-reading',question:'What is a rhetorical question and what effect does it have?',options:['A question that requires a factual answer','A question asked for persuasive effect, not expecting an answer, prompting the reader to reflect','A question about rhetoric','A question at the end of an exam paper'],correctAnswer:1,explanation:'Rhetorical questions are asked to make a point rather than elicit an answer. They engage the reader by prompting them to think and often lead them towards the writer\'s intended conclusion.',difficulty:'foundation'},
           {id:'eng-nr-q9',topicId:'eng-lang2-reading',question:'When comparing viewpoints in Q4, what should you compare alongside what the writers think?',options:['Only the length of each text','The methods each writer uses to convey their viewpoint','The biographical details of each writer','The number of paragraphs in each text'],correctAnswer:1,explanation:'Q4 requires comparison of both viewpoints (what writers think) and methods (how they convey their ideas). Analysing techniques such as language, tone, structure and rhetorical devices shows deeper analytical ability.',difficulty:'intermediate'},
           {id:'eng-nr-q10',topicId:'eng-lang2-reading',question:'A 19th-century writer uses long, complex sentences with multiple subordinate clauses. What does this suggest about the text?',options:['The writer was a poor communicator','This was a typical convention of the period, reflecting a more formal, elaborate prose style','The writer was being paid by the word','The text is poorly written'],correctAnswer:1,explanation:'Long, complex sentences were a standard convention of 19th-century prose. Recognising this as a period feature rather than a flaw shows contextual understanding, which is rewarded in the exam.',difficulty:'higher'},
           {id:'eng-nr-q11',topicId:'eng-lang2-reading',question:'What is an anecdote and why might a non-fiction writer use one?',options:['A type of medicine','A short personal story used to illustrate a point, making the argument more relatable and persuasive','A factual statistic','A type of formal letter'],correctAnswer:1,explanation:'An anecdote is a brief personal story or example used to support an argument. It makes abstract issues concrete and relatable, helping the reader connect emotionally with the writer\'s viewpoint.',difficulty:'intermediate'},
           {id:'eng-nr-q12',topicId:'eng-lang2-reading',question:'Which comparative connective would you use to highlight a difference between two writers\' viewpoints?',options:['"Similarly"','"Both writers"','"In contrast"','"Equally"'],correctAnswer:2,explanation:'"In contrast" signals a difference between the two writers\' perspectives. Using varied comparative connectives (however, whereas, on the other hand, conversely) throughout your response demonstrates sophisticated comparative writing.',difficulty:'foundation'},
           {id:'eng-nr-q13',topicId:'eng-lang2-reading',question:'A modern text uses informal language and slang while a 19th-century text on the same topic uses elevated, formal vocabulary. How should you address this in Q4?',options:['Ignore the language differences','Explain how the different registers reflect the conventions and audiences of their respective time periods','Say one text is better than the other','Only comment on the modern text'],correctAnswer:1,explanation:'Linking language choices to context shows sophisticated analysis. Explaining that differences in register reflect the conventions, audiences and purposes of different periods demonstrates understanding beyond surface-level comparison.',difficulty:'higher'},
           {id:'eng-nr-q14',topicId:'eng-lang2-reading',question:'What is the effect of a writer using a statistic in a non-fiction text?',options:['Statistics always make writing boring','They add factual authority and credibility, making the argument more convincing','Statistics are never used in non-fiction','They replace the need for any other persuasive techniques'],correctAnswer:1,explanation:'Statistics provide factual evidence that lends authority to the writer\'s argument. They can shock the reader, support a claim with hard data, and make the argument appear well-researched and credible.',difficulty:'foundation'},
           {id:'eng-nr-q15',topicId:'eng-lang2-reading',question:'A writer ends their non-fiction piece with a short, punchy sentence after a long, detailed paragraph. What structural effect does this create?',options:['It is a mistake in the writing','The contrast in sentence length creates emphasis on the final point, giving it memorable impact','Short sentences are always bad','It shows the writer ran out of ideas'],correctAnswer:1,explanation:'Ending with a short sentence after a longer passage creates a dramatic contrast that emphasises the final point. This structural choice ensures the concluding idea resonates with the reader and is memorable.',difficulty:'further'}]),
        t('eng-lang2-writing', 'eng-lang2', 'Persuasive & Argumentative Writing', 'Writing speeches, articles, letters and essays to present a viewpoint.',
          'Paper 2 Section B requires you to write a non-fiction text presenting a viewpoint. The task will specify the form (speech, article, letter, or essay) and the audience. Understanding form conventions is crucial: a letter needs addresses and formal openings; a speech needs direct address and rhetorical flourishes; an article needs a headline and may use subheadings; an essay needs a formal, balanced structure.\n\nEffective persuasive writing uses rhetorical techniques to influence the reader. The key devices can be remembered through acronyms like AFOREST: Alliteration, Facts, Opinions, Rhetorical questions, Emotive language, Statistics, and Triples (lists of three). However, simply using these techniques is not enough; they must be embedded naturally and support a clear, sustained argument.\n\nOrganise your writing with a clear introduction that states your position, developed paragraphs that each make a distinct point supported by evidence or examples, and a strong conclusion that reinforces your argument. Use counter-arguments to demonstrate sophistication, acknowledging the opposing view before refuting it. Discourse markers such as "furthermore", "however", and "consequently" help guide the reader through your argument.',
          ['Match your writing to the correct form: letter, speech, article or essay', 'Use AFOREST techniques: Alliteration, Facts, Opinions, Rhetorical questions, Emotive language, Statistics, Triples', 'Structure with clear introduction, developed paragraphs and strong conclusion', 'Include counter-arguments to show sophistication', 'Discourse markers guide the reader through your argument'],
          [{id:'ef10',front:'What does AFOREST stand for?',back:'Alliteration, Facts, Opinions, Rhetorical questions, Emotive language, Statistics, Triples (rule of three).'},{id:'ef11',front:'What conventions does a formal letter need?',back:'Sender\'s address (top right), recipient\'s address (left), date, formal greeting (Dear Sir/Madam), formal sign-off (Yours faithfully/sincerely).'},{id:'ef12',front:'What is a counter-argument and why use one?',back:'Acknowledging the opposing viewpoint before refuting it. This shows sophistication and makes your own argument more persuasive by demonstrating balanced awareness.'}],
          [{id:'eng-pw-q1',topicId:'eng-lang2-writing',question:'You are asked to write a speech to your school about the importance of reading. Which opening is most appropriate?',options:['"Dear Sir/Madam, I am writing to express my views on reading."','"Fellow students, I ask you: when was the last time you picked up a book and lost yourself in its pages?"','"Reading is important. Everyone should read more books. That is a fact."','"Hi guys, so like, books are pretty cool right?"'],correctAnswer:1,explanation:'A speech uses direct address ("Fellow students") and rhetorical questions to engage the audience immediately. The register is appropriate - formal enough for a school setting but engaging and personal.',difficulty:'intermediate'},
           {id:'eng-pw-q2',topicId:'eng-lang2-writing',question:'Which of the following best demonstrates a counter-argument technique?',options:['Reading is the most important skill in the world.','Some may argue that technology has made reading obsolete; however, studies consistently show that reading improves both empathy and cognitive function.','You should read because I said so.','Reading is good and everyone knows it.'],correctAnswer:1,explanation:'A counter-argument first acknowledges the opposing view ("Some may argue...") then refutes it with evidence ("however, studies show..."). This demonstrates balanced, sophisticated writing.',difficulty:'higher'},
           {id:'eng-pw-q3',topicId:'eng-lang2-writing',question:'An article for a newspaper needs which of the following features?',options:['A sender\'s address and formal greeting','A headline and an engaging opening paragraph','Stage directions and character names','Rhyme scheme and stanza structure'],correctAnswer:1,explanation:'An article requires a headline to capture the reader\'s attention and an engaging opening paragraph that draws them in. It may also use subheadings, quotations from experts, and a concluding paragraph.',difficulty:'intermediate'},
           {id:'eng-pw-q4',topicId:'eng-lang2-writing',question:'What does AFOREST stand for?',options:['Always, Frequently, Often, Rarely, Every, Sometimes, Typically','Alliteration, Facts, Opinions, Rhetorical questions, Emotive language, Statistics, Triples','A, For, Every, Student, Test','Adjectives, Fronted adverbials, Openings, Repetition, Endings, Similes, Tenses'],correctAnswer:1,explanation:'AFOREST is a useful mnemonic for persuasive techniques: Alliteration, Facts, Opinions, Rhetorical questions, Emotive language, Statistics, and Triples (the rule of three). These should be embedded naturally, not forced in.',difficulty:'foundation'},
           {id:'eng-pw-q5',topicId:'eng-lang2-writing',question:'What is the "rule of three" (tricolon) and why is it effective?',options:['Writing exactly three paragraphs','Listing three items together for rhythmic emphasis and persuasive impact','Using three different fonts','Reading a text three times'],correctAnswer:1,explanation:'The rule of three groups words or phrases in threes for rhetorical effect, such as "education, dedication and determination." The pattern is memorable, rhythmic and creates a sense of completeness that persuades the reader.',difficulty:'foundation'},
           {id:'eng-pw-q6',topicId:'eng-lang2-writing',question:'A formal letter should end with "Yours faithfully" when:',options:['You know the recipient\'s name','You have addressed the letter "Dear Sir/Madam" (not using a name)','You are writing to a friend','It is a letter of complaint'],correctAnswer:1,explanation:'Use "Yours faithfully" when you have addressed the letter to "Dear Sir/Madam" (unknown recipient). Use "Yours sincerely" when you know the person\'s name, e.g. "Dear Mr Smith." This is an important convention for formal letters.',difficulty:'foundation'},
           {id:'eng-pw-q7',topicId:'eng-lang2-writing',question:'What is a counter-argument and why does it strengthen persuasive writing?',options:['Arguing with the examiner','Acknowledging the opposing viewpoint before refuting it, showing balanced awareness and making your position more convincing','Writing about a different topic','Counting how many arguments you have made'],correctAnswer:1,explanation:'A counter-argument shows you have considered alternative perspectives before rejecting them. This makes your writing appear more balanced and authoritative, and your own argument more convincing because you have addressed potential objections.',difficulty:'intermediate'},
           {id:'eng-pw-q8',topicId:'eng-lang2-writing',question:'Which discourse marker would best introduce a contrasting point?',options:['"Furthermore"','"In addition"','"However"','"Similarly"'],correctAnswer:2,explanation:'"However" introduces a contrasting point or counter-argument. Discourse markers guide the reader through your argument: "furthermore" and "in addition" add supporting points, while "however", "conversely" and "on the other hand" signal a change in direction.',difficulty:'foundation'},
           {id:'eng-pw-q9',topicId:'eng-lang2-writing',question:'You are writing a speech. Which technique would most effectively engage your audience?',options:['Using long, complex sentences throughout','Using direct address, rhetorical questions and the inclusive pronoun "we"','Avoiding all emotional language','Writing in the third person throughout'],correctAnswer:1,explanation:'Speeches are most effective when they directly engage the audience. Direct address ("you"), rhetorical questions, and the inclusive "we" create a sense of shared purpose and make listeners feel personally involved.',difficulty:'intermediate'},
           {id:'eng-pw-q10',topicId:'eng-lang2-writing',question:'What is the difference between a fact and an opinion in persuasive writing?',options:['There is no difference','A fact can be verified as true; an opinion is a personal viewpoint that may be presented as if it were fact','Facts are always long sentences','Opinions are never used in formal writing'],correctAnswer:1,explanation:'Facts are verifiable statements (e.g. "The UK population is over 67 million"). Opinions are subjective views. Skilled persuasive writers sometimes present opinions as if they are facts to make their argument seem more authoritative.',difficulty:'foundation'},
           {id:'eng-pw-q11',topicId:'eng-lang2-writing',question:'What is the purpose of a strong conclusion in persuasive writing?',options:['To introduce new arguments','To reinforce your main argument and leave a lasting impression on the reader','To apologise for your views','To repeat every point you have already made'],correctAnswer:1,explanation:'A strong conclusion summarises your position, reinforces your key argument, and leaves the reader with a memorable final impression. It should not introduce new points but may include a call to action or a powerful final statement.',difficulty:'intermediate'},
           {id:'eng-pw-q12',topicId:'eng-lang2-writing',question:'A student writes a persuasive article but uses only one type of sentence structure throughout. What advice would improve their writing?',options:['Keep using the same structure for consistency','Vary sentence structures: use short sentences for emphasis, complex sentences for developed points, and rhetorical questions for engagement','Only use simple sentences','Only use compound sentences'],correctAnswer:1,explanation:'Sentence variety is essential for high marks. Short sentences create punch and emphasis, complex sentences develop sophisticated ideas, and questions engage the reader. This variety demonstrates conscious craftsmanship.',difficulty:'intermediate'},
           {id:'eng-pw-q13',topicId:'eng-lang2-writing',question:'What tone is most appropriate for a formal essay arguing against school uniform?',options:['Angry and aggressive','Measured, formal and well-reasoned with supporting evidence','Casual and conversational with slang','Humorous throughout with jokes'],correctAnswer:1,explanation:'A formal essay requires a measured, authoritative tone. You should present well-reasoned arguments supported by evidence, use formal register, and avoid slang or excessively emotional language. This makes your argument credible and persuasive.',difficulty:'intermediate'},
           {id:'eng-pw-q14',topicId:'eng-lang2-writing',question:'How can you use an anecdote effectively in persuasive writing?',options:['Tell a long, unrelated story','Include a brief personal story that illustrates your argument, making abstract issues relatable','Anecdotes should never be used in formal writing','Copy a story from the internet'],correctAnswer:1,explanation:'A well-chosen anecdote makes your argument personal and relatable. For example, in a speech about the importance of reading, briefly describing how a book changed your perspective adds emotional weight and engages the audience.',difficulty:'higher'},
           {id:'eng-pw-q15',topicId:'eng-lang2-writing',question:'A student writes: "Everyone knows that homework is pointless and stupid." What is wrong with this as a persuasive technique?',options:['Nothing - it is a strong opening','It uses a sweeping generalisation ("everyone knows") and lacks evidence, weakening the argument rather than strengthening it','It is too short','It needs more adjectives'],correctAnswer:1,explanation:'Sweeping generalisations like "everyone knows" are weak persuasive writing. They can be easily challenged and suggest the writer has no real evidence. Stronger writing uses specific evidence, statistics or expert opinions to support claims.',difficulty:'further'}]),
      ],
    },
    {
      id: 'eng-macbeth', subjectId: 'english', name: 'Shakespeare: Macbeth',
      topics: [
        t('eng-macbeth-themes', 'eng-macbeth', 'Themes in Macbeth', 'Exploring the key themes of ambition, power, guilt, the supernatural, masculinity and appearance vs reality.',
          'Macbeth explores the destructive nature of unchecked ambition. Macbeth\'s ambition is initially sparked by the Witches\' prophecy and fuelled by Lady Macbeth\'s manipulation. Shakespeare shows how ambition without moral restraint leads to tyranny and destruction. The theme connects to the Jacobean belief in the Great Chain of Being: disrupting the natural order through regicide brings chaos to the entire kingdom.\n\nGuilt is a central theme that manifests physically and psychologically. Macbeth hallucinates a dagger before killing Duncan and later sees Banquo\'s ghost. Lady Macbeth\'s guilt emerges in her sleepwalking scene where she obsessively tries to wash imagined blood from her hands. Shakespeare suggests that guilt is an inescapable consequence of immoral action, and that the human conscience cannot be suppressed indefinitely.\n\nThe supernatural pervades the play through the Witches, the apparitions, and the disruption of nature. Shakespeare uses the supernatural to create dramatic tension and to reflect Jacobean anxieties about witchcraft. The theme of appearance versus reality is established from the opening with the Witches\' paradox and runs throughout, as characters hide their true intentions behind false faces.',
          ['Ambition: Macbeth\'s ambition is his tragic flaw (hamartia) leading to his downfall', 'Guilt: manifests as hallucinations (dagger, Banquo\'s ghost) and Lady Macbeth\'s sleepwalking', 'Supernatural: the Witches spark events but Macbeth chooses to act on their prophecies', 'Appearance vs Reality: established by the Witches\' paradox and seen throughout the play', 'Power and Kingship: Shakespeare contrasts tyrannical rule (Macbeth) with good kingship (Duncan, Malcolm)'],
          [{id:'ef13',front:'What is Macbeth\'s hamartia (tragic flaw)?',back:'His unchecked ambition, which is sparked by the Witches\' prophecy and fuelled by Lady Macbeth, ultimately leading to his moral and physical destruction.'},{id:'ef14',front:'How does guilt manifest in Macbeth?',back:'Through hallucinations: Macbeth sees a floating dagger and Banquo\'s ghost. Lady Macbeth sleepwalks and obsessively washes her hands, unable to remove the imagined blood.'},{id:'ef15',front:'What is the Great Chain of Being and why is it relevant?',back:'The Jacobean belief that God ordained a natural hierarchy. Macbeth\'s regicide disrupts this order, causing chaos in nature and the kingdom, reflecting divine displeasure.'}],
          [{id:'eng-mt-q1',topicId:'eng-macbeth-themes',question:'Which theme is most closely linked to Lady Macbeth\'s sleepwalking scene?',options:['The supernatural','Ambition','Guilt','Masculinity'],correctAnswer:2,explanation:'Lady Macbeth\'s sleepwalking scene dramatises the theme of guilt. Her compulsive handwashing and fragmented speech reveal a mind tormented by the murders she helped bring about, showing that guilt cannot be suppressed.',difficulty:'intermediate'},
           {id:'eng-mt-q2',topicId:'eng-macbeth-themes',question:'How does Shakespeare use the theme of appearance vs reality in Macbeth?',options:['By setting the play entirely in darkness','Through characters who disguise their true intentions, beginning with the Witches\' paradox','By making all characters honest and straightforward','Through the use of comedic scenes to lighten the mood'],correctAnswer:1,explanation:'Appearance vs reality runs throughout the play. The Witches establish the theme with their paradox, Lady Macbeth advises Macbeth to appear innocent, and Macbeth hides his murderous intentions behind a loyal facade.',difficulty:'higher'},
           {id:'eng-mt-q3',topicId:'eng-macbeth-themes',question:'Why is the Great Chain of Being important to understanding Macbeth?',options:['It explains the Witches\' magical powers','It shows why Lady Macbeth goes mad','It explains why regicide causes chaos in nature and the kingdom, reflecting Jacobean beliefs about divine order','It is the name of a weapon used in the final battle'],correctAnswer:2,explanation:'The Great Chain of Being was the Jacobean belief that God created a natural hierarchy. Macbeth\'s act of regicide disrupts this divinely ordained order, which is reflected in the unnatural events that follow, such as storms and animals behaving strangely.',difficulty:'higher'},
           {id:'eng-mt-q4',topicId:'eng-macbeth-themes',question:'What is Macbeth\'s hamartia (tragic flaw)?',options:['His kindness','His cowardice','His unchecked ambition','His loyalty to Duncan'],correctAnswer:2,explanation:'Macbeth\'s hamartia is his vaulting ambition. Although initially a loyal and brave warrior, his desire for power overwhelms his moral judgement, leading him to commit regicide and descend into tyranny.',difficulty:'foundation'},
           {id:'eng-mt-q5',topicId:'eng-macbeth-themes',question:'How does the theme of masculinity drive the plot of Macbeth?',options:['It has no impact on the plot','Lady Macbeth questions Macbeth\'s manhood to manipulate him into killing Duncan','Only male characters appear in the play','Macbeth is always confident in his masculinity'],correctAnswer:1,explanation:'Lady Macbeth weaponises ideas of masculinity, challenging Macbeth\'s manhood to goad him into action. This shows how toxic ideals of masculinity can lead to violence, as Macbeth equates murder with being a "real man".',difficulty:'intermediate'},
           {id:'eng-mt-q6',topicId:'eng-macbeth-themes',question:'What do the Witches\' prophecies represent in the context of the play\'s themes?',options:['They represent scientific knowledge','They represent fate and the dangerous temptation of forbidden knowledge, raising questions about free will','They are simply comic relief','They represent the church\'s teachings'],correctAnswer:1,explanation:'The Witches\' prophecies raise fundamental questions about fate versus free will. They tempt Macbeth with knowledge of the future, but Shakespeare leaves it ambiguous whether they control events or simply reveal Macbeth\'s existing desires.',difficulty:'higher'},
           {id:'eng-mt-q7',topicId:'eng-macbeth-themes',question:'Which theme is explored through the motif of blood throughout the play?',options:['Love','Guilt and the irreversible consequences of violence','Comedy','Friendship'],correctAnswer:1,explanation:'Blood is a recurring motif linked to guilt. Macbeth sees imaginary blood on his hands after Duncan\'s murder, and Lady Macbeth obsessively washes her hands in the sleepwalking scene. The motif shows that guilt from violence cannot be erased.',difficulty:'intermediate'},
           {id:'eng-mt-q8',topicId:'eng-macbeth-themes',question:'How does Shakespeare present the theme of kingship through the character of Duncan?',options:['Duncan is a weak and incompetent king','Duncan represents ideal kingship: he is generous, gracious and divinely appointed, making Macbeth\'s regicide all the more heinous','Duncan is a tyrant','Duncan has no relevance to the theme of kingship'],correctAnswer:1,explanation:'Duncan embodies good kingship through his generosity, trust and gratitude. He rewards loyalty and is respected by his subjects. His positive qualities make Macbeth\'s betrayal and murder more shocking and morally reprehensible.',difficulty:'intermediate'},
           {id:'eng-mt-q9',topicId:'eng-macbeth-themes',question:'What is the significance of the Witches\' opening line about "fair" and "foul"?',options:['It describes the weather','It establishes the theme of appearance versus reality, where nothing is as it seems','It is a spelling mistake','It introduces the theme of travel'],correctAnswer:1,explanation:'The paradox establishes that in the world of Macbeth, appearances are deceptive. What seems good ("fair") may be evil ("foul") and vice versa. This theme pervades the play as characters hide their true intentions.',difficulty:'foundation'},
           {id:'eng-mt-q10',topicId:'eng-macbeth-themes',question:'How does Macbeth\'s relationship with the supernatural change throughout the play?',options:['He is always terrified of the Witches','He moves from being startled by the prophecies to actively seeking the Witches out, showing his increasing dependence on dark forces','He never interacts with the supernatural','He ignores all supernatural elements'],correctAnswer:1,explanation:'Initially, Macbeth is startled by the prophecies. Later, he deliberately seeks the Witches out for more information. This progression shows his increasing moral corruption and dependence on supernatural forces to maintain his power.',difficulty:'higher'},
           {id:'eng-mt-q11',topicId:'eng-macbeth-themes',question:'What does the motif of darkness and night represent in Macbeth?',options:['The characters\' preference for evening activities','Evil, secrecy and moral corruption - characters call on darkness to hide their deeds','The play takes place during winter','Nothing significant'],correctAnswer:1,explanation:'Darkness symbolises evil and concealment. Macbeth asks the stars to hide their fires, and Lady Macbeth calls on thick night. Both characters associate darkness with hiding their murderous intentions from heaven and from themselves.',difficulty:'intermediate'},
           {id:'eng-mt-q12',topicId:'eng-macbeth-themes',question:'How does the theme of order versus disorder operate in Macbeth?',options:['The play has no structure','Duncan\'s reign represents order; Macbeth\'s tyranny creates disorder in nature and society, only restored when Malcolm takes the throne','Order is not a theme in the play','Macbeth creates a more ordered kingdom'],correctAnswer:1,explanation:'Shakespeare structures the play around the disruption and restoration of natural order. Duncan\'s good kingship creates stability; Macbeth\'s unnatural seizure of power causes chaos; Malcolm\'s rightful accession restores order, satisfying Jacobean beliefs.',difficulty:'further'},
           {id:'eng-mt-q13',topicId:'eng-macbeth-themes',question:'Which quotation best illustrates the theme of guilt?',options:['"Is this a dagger which I see before me?"','"Will all great Neptune\'s ocean wash this blood clean from my hand?"','"Fair is foul, and foul is fair"','"Look like the innocent flower, but be the serpent under\'t"'],correctAnswer:1,explanation:'Macbeth\'s question about whether an ocean could wash the blood from his hands powerfully conveys the enormity of his guilt. The hyperbole suggests that no amount of cleansing can remove the stain of murder from his conscience.',difficulty:'intermediate'},
           {id:'eng-mt-q14',topicId:'eng-macbeth-themes',question:'Why is the play\'s setting in Scotland politically significant for Shakespeare\'s audience?',options:['Shakespeare preferred Scottish settings','King James I was Scottish, so the play flatters him by exploring Scottish history and themes of legitimate kingship','Scotland was not considered significant','The setting has no political significance'],correctAnswer:1,explanation:'Shakespeare wrote Macbeth partly to flatter King James I, who was Scottish and had recently united the English and Scottish crowns. The play\'s themes of legitimate kingship and the horror of regicide would have resonated with James\'s own political concerns.',difficulty:'further'},
           {id:'eng-mt-q15',topicId:'eng-macbeth-themes',question:'How does Shakespeare suggest that violence breeds more violence in Macbeth?',options:['He does not explore this idea','After killing Duncan, Macbeth must kill Banquo and Macduff\'s family to protect his throne, showing an escalating cycle of bloodshed','Macbeth only commits one murder','Violence in the play is always justified'],correctAnswer:1,explanation:'Shakespeare shows that one act of violence necessitates further violence. Macbeth kills Duncan, then must kill Banquo to prevent the prophecy, then Macduff\'s family out of paranoia. Each murder leads to another, illustrating how tyranny escalates.',difficulty:'higher'}]),
        t('eng-macbeth-characters', 'eng-macbeth', 'Characters in Macbeth', 'Analysis of key characters: Macbeth, Lady Macbeth, Banquo, the Witches, Macduff and Duncan.',
          'Macbeth undergoes a dramatic character arc from a loyal, valiant warrior to a tyrannical king consumed by paranoia. At the start, he is described as "brave Macbeth" and is rewarded for his loyalty. However, his susceptibility to the Witches\' prophecy and his wife\'s manipulation reveals his ambition. After killing Duncan, he becomes increasingly isolated and ruthless, ordering the murders of Banquo and Macduff\'s family without Lady Macbeth\'s involvement.\n\nLady Macbeth is initially presented as the dominant partner who questions her husband\'s masculinity to manipulate him into action. She calls on dark spirits to "unsex" her, rejecting feminine weakness. However, her control unravels as guilt destroys her sanity, and her final appearance in the sleepwalking scene shows a broken, tormented figure. Shakespeare uses her downfall to suggest that suppressing natural human emotion is ultimately impossible.\n\nBanquo serves as a dramatic foil to Macbeth. He hears the same prophecy but chooses not to act on it, highlighting Macbeth\'s moral failure. Duncan represents the ideal king: generous, trusting, and divinely appointed. Macduff embodies loyalty and righteous vengeance, and his grief upon learning of his family\'s murder is one of the play\'s most powerful moments. The Witches are ambiguous figures who catalyse events but do not control Macbeth\'s choices.',
          ['Macbeth: transforms from loyal warrior to tyrannical king, showing ambition\'s corrupting power', 'Lady Macbeth: initially dominant and manipulative, later destroyed by guilt', 'Banquo: foil to Macbeth, resists temptation and remains loyal', 'Duncan: represents ideal kingship through generosity and trust', 'Macduff: embodies loyalty, honour and righteous vengeance against tyranny'],
          [{id:'ef16',front:'How is Lady Macbeth presented at the start of the play?',back:'As the dominant partner who manipulates Macbeth by questioning his masculinity. She calls on dark spirits to remove her feminine qualities, showing her determination and ruthlessness.'},{id:'ef17',front:'Why is Banquo considered a foil to Macbeth?',back:'Banquo hears the same prophecy but chooses not to act on it. His moral restraint highlights Macbeth\'s decision to pursue the crown through murder.'},{id:'ef18',front:'How does Macbeth\'s character change throughout the play?',back:'He transforms from a brave, loyal warrior into a paranoid tyrant. After Duncan\'s murder, he acts increasingly alone, ordering further killings without Lady Macbeth\'s involvement.'}],
          [{id:'eng-mc-q1',topicId:'eng-macbeth-characters',question:'What role does Banquo serve in the play?',options:['He is the main villain who drives the plot','He is a comedic character providing relief','He acts as a foil to Macbeth, highlighting Macbeth\'s moral decline','He is Macbeth\'s loyal servant throughout'],correctAnswer:2,explanation:'Banquo serves as a dramatic foil. He receives the same prophecy but resists the temptation to act immorally, making Macbeth\'s choice to commit murder a clear moral failing rather than an inevitable response.',difficulty:'intermediate'},
           {id:'eng-mc-q2',topicId:'eng-macbeth-characters',question:'How does Shakespeare present Lady Macbeth\'s downfall?',options:['She is killed in battle by Macduff','She gradually loses control as guilt manifests in sleepwalking and obsessive behaviour','She is arrested and put on trial for witchcraft','She simply leaves the play without explanation'],correctAnswer:1,explanation:'Lady Macbeth\'s downfall is psychological. Her sleepwalking scene reveals that the guilt she tried to suppress has overwhelmed her. Her fragmented language and obsessive handwashing contrast sharply with her earlier confidence and control.',difficulty:'higher'},
           {id:'eng-mc-q3',topicId:'eng-macbeth-characters',question:'Why is Duncan\'s characterisation important to the play\'s themes?',options:['His weakness justifies Macbeth\'s actions','His generosity and trust make Macbeth\'s betrayal more shocking and emphasise the evil of regicide','He is an incompetent king who deserves to be replaced','His strict rule causes Macbeth to rebel'],correctAnswer:1,explanation:'Shakespeare presents Duncan as a generous, trusting and divinely appointed king. This makes Macbeth\'s act of regicide all the more heinous, as he is destroying a good and legitimate ruler for personal gain.',difficulty:'higher'},
           {id:'eng-mc-q4',topicId:'eng-macbeth-characters',question:'How is Macbeth described at the very beginning of the play?',options:['As a cowardly traitor','As a brave and loyal warrior who fought valiantly for King Duncan','As an ambitious schemer','As an old and tired soldier'],correctAnswer:1,explanation:'In Act 1, Macbeth is praised as "brave Macbeth" and "Bellona\'s bridegroom" for his courageous fighting. This heroic introduction makes his later moral decline more dramatic and shocking.',difficulty:'foundation'},
           {id:'eng-mc-q5',topicId:'eng-macbeth-characters',question:'What does Lady Macbeth mean when she says "unsex me here"?',options:['She wants to change her physical appearance','She asks dark spirits to remove her feminine qualities of compassion and weakness so she can be ruthless enough to commit murder','She wants to become a man','She is asking for a divorce'],correctAnswer:1,explanation:'Lady Macbeth calls on evil spirits to strip her of feminine qualities like compassion and remorse. This soliloquy reveals her determination and her belief that femininity is incompatible with the ruthlessness needed for murder.',difficulty:'intermediate'},
           {id:'eng-mc-q6',topicId:'eng-macbeth-characters',question:'How does Macbeth\'s attitude towards violence change throughout the play?',options:['He becomes more reluctant to use violence','He moves from hesitation before Duncan\'s murder to ordering killings without remorse, showing moral deterioration','He is always enthusiastic about violence','He never commits violence himself'],correctAnswer:1,explanation:'Macbeth initially agonises over killing Duncan, showing his moral awareness. By Act 3, he orders Banquo\'s murder without consulting Lady Macbeth, and by Act 4, he has Macduff\'s entire family slaughtered. This escalation shows his complete moral corruption.',difficulty:'intermediate'},
           {id:'eng-mc-q7',topicId:'eng-macbeth-characters',question:'What is the dramatic function of Macduff in the play?',options:['He provides comic relief','He represents loyalty, honour and righteous vengeance against tyranny','He is the main villain','He is Macbeth\'s closest friend'],correctAnswer:1,explanation:'Macduff embodies the virtues that Macbeth has abandoned: loyalty, honour and love for his country. His grief over his family\'s murder and his role in defeating Macbeth make him the instrument of justice and moral restoration.',difficulty:'intermediate'},
           {id:'eng-mc-q8',topicId:'eng-macbeth-characters',question:'Why is the relationship between Macbeth and Lady Macbeth significant?',options:['It shows a typical happy marriage','It demonstrates how their power dynamic shifts: she initially dominates, but he gradually acts alone as she is consumed by guilt','They have no real relationship in the play','Their relationship stays exactly the same throughout'],correctAnswer:1,explanation:'Their shifting dynamic reflects the play\'s themes. Lady Macbeth initially drives events, but after Duncan\'s murder, Macbeth becomes increasingly independent and secretive while she deteriorates psychologically. Their growing isolation mirrors the consequences of their actions.',difficulty:'higher'},
           {id:'eng-mc-q9',topicId:'eng-macbeth-characters',question:'What is the significance of the Porter scene (Act 2, Scene 3)?',options:['It has no significance','It provides comic relief but also creates dramatic irony, as the Porter unknowingly references hell and damnation, echoing the evil that has just occurred','It is the most important scene in the play','It introduces the main plot'],correctAnswer:1,explanation:'The Porter\'s drunken comedy provides a moment of relief after Duncan\'s murder, but his references to hell-gate create dramatic irony. The audience knows that hell-like evil has indeed entered Macbeth\'s castle, deepening the horror.',difficulty:'higher'},
           {id:'eng-mc-q10',topicId:'eng-macbeth-characters',question:'How are the Witches presented and what role do they play?',options:['They are clearly evil and fully responsible for Macbeth\'s actions','They are ambiguous figures who catalyse events through prophecy but do not force Macbeth to act','They are friendly and helpful','They appear only once in the play'],correctAnswer:1,explanation:'The Witches are deliberately ambiguous. They offer prophecies that tempt Macbeth but never explicitly tell him to kill. This raises questions about fate versus free will: did they cause events or simply reveal what Macbeth already desired?',difficulty:'intermediate'},
           {id:'eng-mc-q11',topicId:'eng-macbeth-characters',question:'What does Malcolm\'s characterisation at the end of the play suggest?',options:['He will be a worse king than Macbeth','He represents the restoration of legitimate, rightful kingship after the chaos of tyranny','He is an unimportant character','He will continue Macbeth\'s violent methods'],correctAnswer:1,explanation:'Malcolm\'s restoration to the throne represents the return of legitimate, divinely sanctioned order. His final speech, rewarding loyal followers and restoring stability, contrasts sharply with Macbeth\'s tyranny and satisfies the audience\'s desire for justice.',difficulty:'intermediate'},
           {id:'eng-mc-q12',topicId:'eng-macbeth-characters',question:'How does Shakespeare use soliloquies to develop Macbeth\'s character?',options:['Macbeth never has soliloquies','Soliloquies reveal his inner conflict, moral awareness and gradual descent into despair, giving the audience access to his psychological state','Soliloquies are only used by Lady Macbeth','They are used for comedy'],correctAnswer:1,explanation:'Macbeth\'s soliloquies are crucial for character development. They reveal his internal struggle before Duncan\'s murder, his growing paranoia, and his ultimate despair. They create a complex, psychologically rich character rather than a simple villain.',difficulty:'higher'},
           {id:'eng-mc-q13',topicId:'eng-macbeth-characters',question:'What does Lady Macbeth\'s dialogue in the sleepwalking scene reveal about her character?',options:['She is perfectly healthy and happy','Her fragmented, disjointed speech reveals a mind destroyed by guilt, contrasting sharply with her earlier controlled, commanding language','She is pretending to be asleep','She is rehearsing a speech'],correctAnswer:1,explanation:'In Act 5 Scene 1, Lady Macbeth speaks in fragmented prose rather than her earlier controlled verse. Her compulsive handwashing and references to blood reveal that the guilt she tried to suppress has completely overwhelmed her sanity.',difficulty:'further'},
           {id:'eng-mc-q14',topicId:'eng-macbeth-characters',question:'Why does Banquo\'s ghost appear at the banquet?',options:['It is a party trick','The ghost represents Macbeth\'s guilty conscience manifesting as a hallucination, publicly exposing the psychological consequences of his crimes','Banquo is still alive','It is a different character in disguise'],correctAnswer:1,explanation:'Banquo\'s ghost is visible only to Macbeth, suggesting it represents his guilty conscience rather than a literal supernatural event. His terrified reaction publicly exposes his inner turmoil and almost reveals his guilt to the other guests.',difficulty:'intermediate'},
           {id:'eng-mc-q15',topicId:'eng-macbeth-characters',question:'How does Shakespeare use Macbeth\'s final speeches to create a complex response in the audience?',options:['The audience simply hates Macbeth by the end','His speeches about the meaninglessness of life create pathos and tragic grandeur, prompting some sympathy even as we recognise his evil','His final speeches are unimportant','He does not speak at the end of the play'],correctAnswer:1,explanation:'Macbeth\'s later soliloquies, particularly his reflection on life as "a tale told by an idiot", create a complex audience response. While we condemn his actions, his despair and nihilism evoke a degree of pity, making him a true tragic figure.',difficulty:'further'}]),
      ],
    },
    {
      id: 'eng-19c', subjectId: 'english', name: '19th Century Novel',
      topics: [
        t('eng-19c-context', 'eng-19c', '19th Century Context and Conventions', 'Understanding Victorian society, the Gothic genre, social class and industrialisation.',
          'The 19th century was a period of enormous social, economic and technological change in Britain. The Industrial Revolution transformed the country from an agricultural society into an urban, industrial one. This created immense wealth for factory owners and the middle class, but also appalling poverty, child labour and overcrowded slums. Many 19th-century novelists used their fiction to highlight these social injustices and campaign for reform.\n\nVictorian society was rigidly hierarchical, with clear divisions between the upper, middle and working classes. Social mobility was difficult, and a person\'s birth largely determined their opportunities. Gender roles were strictly defined: men were expected to work and provide, while women were confined to the domestic sphere. The concept of the "Angel in the House" idealised women as pure, submissive homemakers. Many novels of the period explore characters who challenge or are constrained by these expectations.\n\nThe Gothic genre was hugely popular in the 19th century, characterised by dark, atmospheric settings (old castles, moors, graveyards), supernatural elements, psychological terror and themes of isolation. Writers such as Shelley, Stevenson and Stoker used Gothic conventions to explore anxieties about science, morality and the darker side of human nature. Understanding these conventions helps you analyse how 19th-century writers create atmosphere, develop character and convey social commentary.',
          ['Industrial Revolution created both wealth and widespread poverty, child labour and poor conditions', 'Victorian society was divided by rigid social class with limited mobility', 'Gender roles confined women to domestic roles as the idealised "Angel in the House"', 'The Gothic genre used dark settings, supernatural elements and psychological terror', 'Many 19th-century novelists used fiction as social commentary to highlight injustice'],
          [{id:'ef19',front:'What was the "Angel in the House"?',back:'A Victorian ideal of femininity: women were expected to be pure, submissive, devoted homemakers. Many 19th-century novels explore female characters who challenge or suffer under this expectation.'},{id:'ef20',front:'Name three conventions of the Gothic genre.',back:'Dark, isolated settings (castles, moors, graveyards); supernatural or unexplained events; psychological terror and exploration of fear, madness or the uncanny.'},{id:'ef21',front:'How did the Industrial Revolution affect 19th-century literature?',back:'Many writers used fiction to highlight the social injustices caused by industrialisation, including poverty, child labour, class division and the dehumanising conditions in factories and workhouses.'}],
          [{id:'eng-cc-q1',topicId:'eng-19c-context',question:'Which of the following best describes the impact of the Industrial Revolution on Victorian society?',options:['It improved conditions equally for all classes','It created wealth for some but also caused poverty, overcrowding and child labour','It had no significant social impact','It primarily affected rural communities, not cities'],correctAnswer:1,explanation:'The Industrial Revolution created enormous wealth for factory owners and the emerging middle class, but also led to appalling conditions for the working class, including poverty, child labour, overcrowded slums and dangerous working conditions.',difficulty:'intermediate'},
           {id:'eng-cc-q2',topicId:'eng-19c-context',question:'How might an understanding of Victorian gender roles help you analyse a 19th-century novel?',options:['It is not relevant to literary analysis','It helps you understand why female characters may be restricted in their choices and how some writers challenge or reinforce these expectations','It only matters for texts written by female authors','It explains the plot but not the themes'],correctAnswer:1,explanation:'Understanding Victorian gender norms helps you analyse how female characters are presented and whether the writer reinforces or subverts expectations. It reveals layers of social commentary in the text.',difficulty:'higher'},
           {id:'eng-cc-q3',topicId:'eng-19c-context',question:'Which features are typical of the Gothic genre?',options:['Bright, cheerful settings and comedic plots','Dark, isolated settings, supernatural elements, and psychological terror','Detailed scientific explanations and factual reporting','Simple, everyday domestic settings with no conflict'],correctAnswer:1,explanation:'The Gothic genre is characterised by dark, atmospheric settings, supernatural or unexplained events, and a focus on psychological terror and the exploration of fear, madness and the uncanny.',difficulty:'intermediate'},
           {id:'eng-cc-q4',topicId:'eng-19c-context',question:'What was the main consequence of the Industrial Revolution for the working class?',options:['Universal wealth and prosperity','Appalling poverty, dangerous working conditions, child labour and overcrowded slums','Improved education for all','Better housing conditions'],correctAnswer:1,explanation:'While the Industrial Revolution created wealth for factory owners and the middle class, it brought terrible conditions for the working class: long hours, dangerous factories, child labour, poverty and overcrowded urban slums.',difficulty:'foundation'},
           {id:'eng-cc-q5',topicId:'eng-19c-context',question:'What does "social mobility" mean in a Victorian context?',options:['Moving between different cities','The ability to move between social classes, which was very limited in Victorian society','Travelling by horse and carriage','Social media use'],correctAnswer:1,explanation:'Social mobility refers to the ability to improve one\'s social and economic position. In Victorian England, this was extremely difficult as birth largely determined opportunity. Many novels explore characters attempting to transcend their class.',difficulty:'foundation'},
           {id:'eng-cc-q6',topicId:'eng-19c-context',question:'Why did many 19th-century novelists write about social issues?',options:['They were paid extra for social commentary','They used fiction to highlight injustices such as poverty, inequality and child labour, campaigning for reform','They had no other topics to write about','The government told them what to write'],correctAnswer:1,explanation:'Many Victorian novelists were social reformers who used their fiction to draw public attention to injustices. Dickens, for example, highlighted the cruelty of workhouses, debtors\' prisons and child exploitation to provoke public outrage and demand change.',difficulty:'intermediate'},
           {id:'eng-cc-q7',topicId:'eng-19c-context',question:'What was the role of religion in Victorian society?',options:['Religion was unimportant','Christianity was central to Victorian life, influencing moral codes, social expectations and attitudes towards science and progress','Only the upper classes were religious','Religion played no role in literature'],correctAnswer:1,explanation:'Religion shaped virtually every aspect of Victorian life. Christian morality influenced social expectations, attitudes to poverty and charity, and anxieties about scientific discoveries like Darwin\'s theory of evolution, which challenged religious beliefs.',difficulty:'intermediate'},
           {id:'eng-cc-q8',topicId:'eng-19c-context',question:'What is meant by the "separate spheres" ideology in Victorian England?',options:['A scientific theory about planets','The belief that men belonged in the public sphere (work, politics) while women belonged in the domestic sphere (home, family)','Different rooms in a Victorian house','A type of Victorian sport'],correctAnswer:1,explanation:'The doctrine of separate spheres rigidly divided gender roles: men occupied the public world of work, politics and commerce, while women were confined to the home. This ideology limited women\'s opportunities and is challenged by many 19th-century writers.',difficulty:'intermediate'},
           {id:'eng-cc-q9',topicId:'eng-19c-context',question:'How did Charles Darwin\'s theory of evolution affect Victorian society?',options:['It had no impact','It challenged religious beliefs about creation, causing widespread anxiety and debate about the relationship between science and faith','Everyone immediately accepted it','It only affected scientists'],correctAnswer:1,explanation:'Darwin\'s theory of evolution challenged the biblical account of creation and provoked a crisis of faith in Victorian society. This tension between science and religion is reflected in literature of the period, particularly in Gothic and speculative fiction.',difficulty:'higher'},
           {id:'eng-cc-q10',topicId:'eng-19c-context',question:'What was a workhouse and why is it relevant to 19th-century literature?',options:['A type of factory that made houses','An institution where the poor were forced to live and work in harsh conditions, often depicted in novels to criticise the treatment of the poor','A school for builders','A workshop for artists'],correctAnswer:1,explanation:'Workhouses were institutions where destitute people were forced to live and labour in appalling conditions. They separated families and treated residents with deliberate harshness. Writers like Dickens used them as symbols of society\'s cruel treatment of the poor.',difficulty:'intermediate'},
           {id:'eng-cc-q11',topicId:'eng-19c-context',question:'How does understanding the British Empire help when studying 19th-century literature?',options:['It is not relevant','It provides context for attitudes towards race, colonialism and cultural superiority that may appear in texts of the period','The Empire is never mentioned in literature','It only matters for history exams'],correctAnswer:1,explanation:'The British Empire shaped Victorian attitudes towards other cultures and races. Understanding imperial ideology helps you analyse how 19th-century texts may reflect, reinforce or challenge assumptions about cultural superiority and colonial power.',difficulty:'higher'},
           {id:'eng-cc-q12',topicId:'eng-19c-context',question:'What is a "Bildungsroman" and which 19th-century novels follow this pattern?',options:['A type of Victorian crime fiction','A coming-of-age novel that follows the moral and psychological growth of a protagonist from youth to adulthood','A German cooking recipe','A type of poetry from the 19th century'],correctAnswer:1,explanation:'A Bildungsroman traces a character\'s development from youth to maturity. Many Victorian novels follow this pattern, exploring how social conditions, class and personal choices shape identity and moral growth.',difficulty:'higher'},
           {id:'eng-cc-q13',topicId:'eng-19c-context',question:'Why might a 19th-century Gothic text feature a setting like a remote castle or isolated mansion?',options:['Victorian architects loved castles','Isolated settings create claustrophobia, entrapment and vulnerability, reflecting themes of psychological confinement and hidden secrets','All 19th-century people lived in castles','Castles were fashionable in literature'],correctAnswer:1,explanation:'Gothic settings like remote castles or decaying mansions serve thematic purposes: they create isolation, claustrophobia and vulnerability. The physical entrapment mirrors psychological entrapment, and hidden rooms and passages reflect concealed secrets and repressed desires.',difficulty:'intermediate'},
           {id:'eng-cc-q14',topicId:'eng-19c-context',question:'What was the significance of the 1870 Education Act for Victorian society?',options:['It abolished all schools','It introduced compulsory elementary education for children, reflecting growing recognition that education was essential for social progress','It only affected wealthy families','It had no lasting impact'],correctAnswer:1,explanation:'The 1870 Education Act made elementary education available to all children. This was significant because it reflected changing attitudes towards childhood, social responsibility and the belief that education could improve lives and reduce poverty.',difficulty:'further'},
           {id:'eng-cc-q15',topicId:'eng-19c-context',question:'How does knowledge of the Victorian class system help you analyse a 19th-century novel?',options:['It does not help at all','It helps you understand characters\' motivations, limitations and relationships, and recognise social commentary about inequality and privilege','Class is never mentioned in Victorian novels','It only helps with history questions'],correctAnswer:1,explanation:'The rigid Victorian class system profoundly influenced characters\' opportunities, relationships and identities. Understanding class divisions helps you recognise social commentary, explain characters\' behaviour and analyse the writer\'s critique of inequality.',difficulty:'foundation'}]),
        t('eng-19c-analysis', 'eng-19c', 'Analysing 19th Century Prose', 'Language techniques, narrative perspective and themes in 19th-century texts.',
          'When analysing 19th-century prose, you must consider both the writer\'s methods and the context in which they were writing. Language analysis should focus on the effects of specific word choices, imagery and literary devices. Victorian writers frequently used pathetic fallacy to reflect characters\' emotions, symbolism to represent abstract ideas, and extended metaphors to develop complex themes throughout a text.\n\nNarrative perspective is crucial in 19th-century fiction. First-person narration creates intimacy and can reveal a character\'s inner turmoil, but may also be unreliable. Third-person omniscient narration allows the writer to comment on society and guide the reader\'s moral judgement. Some writers use multiple narrators or epistolary forms (letters) to present different perspectives on events. Understanding the narrative voice helps you analyse how the writer shapes the reader\'s response.\n\nThematic analysis of 19th-century novels requires you to connect the writer\'s ideas to their social and historical context. Common themes include social class and inequality, the conflict between individual desire and social expectation, the nature of good and evil, the effects of isolation, and the tension between science and religion. Always consider what the writer might be suggesting to their contemporary audience about these issues.',
          ['Analyse specific word choices and their connotations in context', 'Identify pathetic fallacy, symbolism and extended metaphor as key Victorian techniques', 'Consider narrative perspective: first-person, third-person omniscient, or multiple narrators', 'Link themes to social and historical context for deeper analysis', 'Use the PEE/PEEL structure to organise analytical paragraphs effectively'],
          [{id:'ef22',front:'What is pathetic fallacy?',back:'A literary technique where the weather or natural environment reflects the mood or emotions of a character. Common in Victorian fiction to create atmosphere.'},{id:'ef23',front:'Why is narrative perspective important in 19th-century novels?',back:'It shapes how the reader receives information and forms judgements. First-person creates intimacy but may be unreliable; third-person omniscient allows the writer to guide moral interpretation.'},{id:'ef24',front:'How should you connect analysis to context in a literature essay?',back:'Link the writer\'s choices to the social, historical or literary context. Explain what the writer might be suggesting to their contemporary audience about issues like class, gender or morality.'}],
          [{id:'eng-ca-q1',topicId:'eng-19c-analysis',question:'A 19th-century writer describes a storm breaking just as the protagonist makes a morally wrong decision. What technique is this?',options:['Foreshadowing','Pathetic fallacy','Onomatopoeia','Dramatic irony'],correctAnswer:1,explanation:'Pathetic fallacy is the technique of using weather or the natural environment to reflect a character\'s emotional state or the moral atmosphere of a scene. The storm mirrors the character\'s moral turmoil.',difficulty:'intermediate'},
           {id:'eng-ca-q2',topicId:'eng-19c-analysis',question:'What is the advantage of a first-person narrator in a 19th-century novel?',options:['It guarantees the narrator is telling the truth','It creates intimacy and allows direct access to the character\'s thoughts and feelings','It means the novel is autobiographical','It allows the writer to describe events they did not witness'],correctAnswer:1,explanation:'First-person narration creates a sense of intimacy between the reader and the narrator, providing direct access to thoughts and emotions. However, it can also be unreliable, as the narrator may have limited perspective or bias.',difficulty:'intermediate'},
           {id:'eng-ca-q3',topicId:'eng-19c-analysis',question:'Why is it important to consider historical context when analysing a 19th-century novel?',options:['To make your essay longer','Because the exam always has a context question','To understand how the writer\'s choices reflect and comment on the society of their time, adding depth to your analysis','Context is not important for literary analysis'],correctAnswer:2,explanation:'Historical context enriches analysis by helping you understand why writers made particular choices. A novel about poverty means more when you understand Victorian workhouses and class division. Context reveals layers of social commentary.',difficulty:'higher'},
           {id:'eng-ca-q4',topicId:'eng-19c-analysis',question:'What is symbolism in literature?',options:['Using symbols instead of words','When an object, character or event represents a deeper meaning or abstract idea beyond its literal significance','A type of spelling system','Drawing pictures in the margins'],correctAnswer:1,explanation:'Symbolism is when concrete things represent abstract ideas. For example, a locked door might symbolise repression or secrets, while a storm could symbolise emotional turmoil. Victorian writers frequently used symbolism to explore themes indirectly.',difficulty:'foundation'},
           {id:'eng-ca-q5',topicId:'eng-19c-analysis',question:'What is an unreliable narrator and why might a 19th-century writer use one?',options:['A narrator who makes spelling mistakes','A narrator whose account may be biased, limited or deliberately misleading, creating suspense and inviting the reader to question the truth','A narrator who forgets the plot','A narrator who speaks quietly'],correctAnswer:1,explanation:'An unreliable narrator is one whose perspective cannot be fully trusted. This technique creates suspense, invites the reader to look beyond the surface, and can reveal the narrator\'s psychological state or moral blindness.',difficulty:'intermediate'},
           {id:'eng-ca-q6',topicId:'eng-19c-analysis',question:'How does an omniscient third-person narrator differ from a first-person narrator in Victorian fiction?',options:['There is no difference','An omniscient narrator knows all characters\' thoughts and can comment on society, while first-person is limited to one perspective','First-person is always more reliable','Third-person is always less interesting'],correctAnswer:1,explanation:'An omniscient narrator can access any character\'s thoughts and provide moral commentary on events, guiding the reader\'s judgement. First-person narration is limited to one perspective but creates intimacy and can raise questions about reliability.',difficulty:'intermediate'},
           {id:'eng-ca-q7',topicId:'eng-19c-analysis',question:'What is an extended metaphor and how is it used in 19th-century prose?',options:['A very long word','A metaphor that is developed and sustained across several sentences or a whole passage, creating a unified thematic thread','A metaphor that is used incorrectly','The same as a simile'],correctAnswer:1,explanation:'An extended metaphor develops a single comparison over multiple sentences or an entire section. Victorian writers used extended metaphors to explore complex themes in depth, creating rich symbolic patterns throughout their texts.',difficulty:'intermediate'},
           {id:'eng-ca-q8',topicId:'eng-19c-analysis',question:'A 19th-century writer describes a character\'s home as having "windows like hollow eyes" and "a door that gaped open like a mouth." What technique is being used?',options:['Alliteration','Personification of the house, giving it human features to create an unsettling, Gothic atmosphere','Onomatopoeia','Hyperbole'],correctAnswer:1,explanation:'The writer personifies the house by giving it human features (eyes, mouth). This creates an eerie, Gothic atmosphere suggesting the building is alive or watching. It reflects the Victorian Gothic tradition of using settings to create psychological unease.',difficulty:'intermediate'},
           {id:'eng-ca-q9',topicId:'eng-19c-analysis',question:'What is the PEE paragraph structure?',options:['A way of organising science experiments','Point, Evidence, Explain - a framework for structuring analytical paragraphs in literature essays','Plan, Execute, Evaluate','Predict, Estimate, Examine'],correctAnswer:1,explanation:'PEE stands for Point (make a clear analytical statement), Evidence (support with a quotation), Explain (analyse the effect of specific words and techniques). This framework ensures your analysis is structured and supported.',difficulty:'foundation'},
           {id:'eng-ca-q10',topicId:'eng-19c-analysis',question:'How should you integrate context into a 19th-century literature essay?',options:['Write a separate paragraph about context at the start','Weave contextual understanding into your analysis of language and themes, showing how the writer reflects or challenges their society','Context should not be included','Copy historical facts from the internet'],correctAnswer:1,explanation:'Context should be woven into analysis rather than bolted on. Instead of separate context paragraphs, show how the writer\'s choices reflect their historical moment. For example, link a character\'s treatment to Victorian attitudes about class.',difficulty:'higher'},
           {id:'eng-ca-q11',topicId:'eng-19c-analysis',question:'What is the effect of a 19th-century writer using dialect or non-standard English for certain characters?',options:['It shows the writer cannot spell correctly','It establishes social class, creates authentic characterisation and may highlight class divisions or social prejudice','It makes the text harder to read for no reason','It is a sign of poor writing'],correctAnswer:1,explanation:'Dialect reflects a character\'s social class, regional identity and education level. Victorian writers used it to create authentic voices and highlight class divisions. The contrast between standard and non-standard English often underscores social inequality.',difficulty:'higher'},
           {id:'eng-ca-q12',topicId:'eng-19c-analysis',question:'What is foreshadowing and how might a 19th-century writer use it?',options:['Drawing shadows in illustrations','Planting clues or hints about future events in the narrative, creating tension and a sense of inevitability','Writing in very dark ink','Describing shadows in the setting'],correctAnswer:1,explanation:'Foreshadowing involves hints about what will happen later, building tension and anticipation. A Victorian writer might describe ominous weather, use dark imagery or have a character make a seemingly innocent comment that gains significance later.',difficulty:'foundation'},
           {id:'eng-ca-q13',topicId:'eng-19c-analysis',question:'A 19th-century novel presents a female character who is initially rebellious but eventually conforms to social expectations. How should you analyse this?',options:['Ignore the change','Consider whether the writer endorses or critiques social conformity by examining how the character\'s submission is presented - as positive resolution or tragic loss of identity','The character simply grew up','All female characters in Victorian novels conform'],correctAnswer:1,explanation:'You should consider the writer\'s intention. If the conformity is presented as positive, the writer may endorse Victorian values. If it feels like a loss of identity, the writer may be critiquing the constraints placed on women. Tone and presentation are key.',difficulty:'further'},
           {id:'eng-ca-q14',topicId:'eng-19c-analysis',question:'What is the epistolary form and why might a 19th-century writer choose it?',options:['A type of poetry','A narrative told through letters, diary entries or documents, creating intimacy and multiple perspectives','A style of architecture','A medical term'],correctAnswer:1,explanation:'The epistolary form uses letters, diaries or documents to tell a story. It creates immediacy and intimacy, allows multiple perspectives, and can make events feel more authentic. Writers like Shelley and Stoker used this form in their Gothic novels.',difficulty:'intermediate'},
           {id:'eng-ca-q15',topicId:'eng-19c-analysis',question:'How should you analyse the ending of a 19th-century novel?',options:['Simply summarise what happens','Consider whether the ending resolves themes, reinforces or challenges social norms, and what the writer is suggesting to their reader about morality or society','The ending is not important','Only discuss the ending if it is happy'],correctAnswer:1,explanation:'Analysing the ending requires considering how it relates to the text\'s themes and the writer\'s purpose. Does it restore social order? Challenge expectations? Provide moral instruction? The ending often reveals the writer\'s central message.',difficulty:'higher'}]),
      ],
    },
    {
      id: 'eng-poetry', subjectId: 'english', name: 'Poetry Anthology',
      topics: [
        t('eng-poetry-power', 'eng-poetry', 'Power and Conflict Poetry', 'Key poems, themes of power, conflict, memory and nature in the AQA anthology.',
          'The AQA Power and Conflict poetry anthology contains 15 poems exploring themes of power, conflict, memory and identity. The poems span different time periods and perspectives, from the Romantic era to contemporary poetry. Each poem offers a distinct viewpoint on how power operates, how conflict affects individuals and societies, and how memory shapes our understanding of events.\n\nKey themes running through the anthology include: the abuse and limitations of human power (seen in poems about political leaders and warfare); the power of nature versus human power (explored through poems about storms, landscapes and natural forces); the effects of conflict on individuals (examining trauma, loss, identity and memory); and the tension between personal experience and public narratives of war and power. Understanding these thematic connections is essential for the comparison question in the exam.\n\nWhen analysing individual poems, focus on the poet\'s methods: structural choices (form, stanza pattern, enjambment, caesura), language techniques (imagery, metaphor, tone, register), and how these methods convey the poem\'s message about power or conflict. Consider why the poet chose a particular form or voice, and how the poem\'s structure reflects its meaning. For example, a poem about chaos might use irregular structure, while one about control might use a rigid, disciplined form.',
          ['The anthology contains 15 poems exploring power, conflict, memory and identity', 'Key themes: abuse of power, nature vs human power, effects of conflict, memory and trauma', 'Analyse methods: structure (form, enjambment, caesura), language (imagery, metaphor, tone)', 'Consider how form and structure reflect the poem\'s meaning and message', 'You must compare a named poem with one of your choice in the exam'],
          [{id:'ef25',front:'What are the main themes in the Power and Conflict anthology?',back:'Power and its abuse, the power of nature versus humanity, the effects of conflict on individuals, memory, identity, loss and trauma.'},{id:'ef26',front:'What is enjambment and what effect can it create?',back:'When a sentence or phrase runs over from one line to the next without punctuation. It can create a sense of momentum, urgency, or reflect ideas that overflow or cannot be contained.'},{id:'ef27',front:'What is caesura and how is it used?',back:'A pause in the middle of a line of poetry, usually created by punctuation. It can create a sense of interruption, conflict, reflection, or a dramatic pause for emphasis.'}],
          [{id:'eng-pp-q1',topicId:'eng-poetry-power',question:'A poem uses irregular line lengths, no consistent rhyme scheme and frequent enjambment. What might this structural choice reflect?',options:['The poet was careless about structure','The chaotic, uncontrollable nature of the conflict or power being described','The poem is not about power or conflict','The poet wanted to make the poem easy to read'],correctAnswer:1,explanation:'Structural choices are deliberate. Irregular form, lack of rhyme and enjambment can reflect chaos, loss of control, or the overwhelming nature of the experience being described. Form mirrors meaning.',difficulty:'higher'},
           {id:'eng-pp-q2',topicId:'eng-poetry-power',question:'Which of the following best describes a key theme explored across the Power and Conflict anthology?',options:['The importance of following rules','How nature is always peaceful and calming','The effects of conflict on individual identity and memory','Why politicians make good leaders'],correctAnswer:2,explanation:'A major theme across the anthology is how conflict affects individuals: their identity, memory and psychological state. Many poems explore the lasting trauma and changed perspectives that result from experiencing or witnessing conflict.',difficulty:'intermediate'},
           {id:'eng-pp-q3',topicId:'eng-poetry-power',question:'When analysing a poem from the anthology, what should you consider alongside language techniques?',options:['Only the poet\'s biography','Structural choices such as form, stanza pattern, enjambment and caesura','The poem\'s page number in the anthology','Whether the poem rhymes or not, with no further analysis'],correctAnswer:1,explanation:'A thorough analysis considers both language and structure. Structural elements like form, stanza pattern, line length, enjambment and caesura all contribute to the poem\'s meaning and should be analysed alongside imagery and other language features.',difficulty:'intermediate'},
           {id:'eng-pp-q4',topicId:'eng-poetry-power',question:'What is enjambment?',options:['A type of rhyme','When a sentence or phrase runs over from one line to the next without end-stopping punctuation','A French word for poem','The title of a poem'],correctAnswer:1,explanation:'Enjambment occurs when a sentence continues past the end of a line without punctuation. It creates a sense of momentum, urgency or overflow, and can suggest ideas that cannot be contained or controlled.',difficulty:'foundation'},
           {id:'eng-pp-q5',topicId:'eng-poetry-power',question:'What is the difference between a poem\'s "form" and its "structure"?',options:['They mean exactly the same thing','Form refers to the overall type of poem (sonnet, dramatic monologue, free verse); structure refers to how ideas are organised within it','Form is about content; structure is about themes','There is no meaningful difference'],correctAnswer:1,explanation:'Form is the overall shape and type of poem (sonnet, ballad, free verse, dramatic monologue). Structure is how ideas, images and arguments are organised within the poem, including shifts in tone, focus or perspective.',difficulty:'intermediate'},
           {id:'eng-pp-q6',topicId:'eng-poetry-power',question:'A poem about war uses regular, disciplined stanzas with a strict rhyme scheme. What might this structural choice reflect?',options:['The poet was lazy','The rigid structure could reflect military discipline, control or the attempt to impose order on the chaos of conflict','Regular structure means the poem is not about conflict','Rhyme schemes are never significant'],correctAnswer:1,explanation:'Structural choices always carry meaning. A rigid, disciplined form in a war poem might reflect military order, a soldier\'s attempt to control chaotic experiences, or the contrast between the orderliness of structure and the disorder of conflict.',difficulty:'higher'},
           {id:'eng-pp-q7',topicId:'eng-poetry-power',question:'What does "volta" mean in poetry?',options:['A type of electrical device','A turning point or shift in a poem where the argument, tone or focus changes direction','The poet\'s name','The last line of a poem'],correctAnswer:1,explanation:'A volta is a turning point in a poem where there is a significant shift in argument, tone, mood or perspective. In a sonnet, the volta traditionally occurs before the final couplet or at the start of the sestet.',difficulty:'intermediate'},
           {id:'eng-pp-q8',topicId:'eng-poetry-power',question:'Why is it important to consider the poet\'s use of voice and perspective in Power and Conflict poems?',options:['It is not important','The choice of speaker shapes how the reader experiences power and conflict - a soldier\'s voice differs from a civilian\'s or a ruler\'s','All poems use the same voice','Voice only matters in novels'],correctAnswer:1,explanation:'The speaker\'s identity and perspective are crucial. A first-person account of conflict creates intimacy and immediacy. A dramatic monologue of a powerful figure reveals arrogance or insecurity. The choice of voice shapes the reader\'s emotional and intellectual response.',difficulty:'intermediate'},
           {id:'eng-pp-q9',topicId:'eng-poetry-power',question:'What effect does a poet create by using violent or aggressive imagery in a poem about power?',options:['It makes the poem unsuitable for study','It can convey the destructive nature of power, the brutality of conflict, or the speaker\'s anger and frustration','Violent imagery has no particular effect','It shows the poet is angry at the reader'],correctAnswer:1,explanation:'Violent imagery creates visceral impact and conveys the physical and emotional reality of conflict or the destructive nature of power. It forces the reader to confront uncomfortable truths rather than viewing power and conflict abstractly.',difficulty:'intermediate'},
           {id:'eng-pp-q10',topicId:'eng-poetry-power',question:'How does the theme of memory operate across the Power and Conflict anthology?',options:['Memory is not a theme in the anthology','Several poems explore how memories of conflict persist, haunt individuals, and shape identity long after events have passed','All the poems are about forgetting','Memory only appears in one poem'],correctAnswer:1,explanation:'Memory is a significant thread across the anthology. Poems explore how traumatic memories persist, how individuals process experiences of conflict, and how personal and collective memories of power and war shape identity and understanding.',difficulty:'higher'},
           {id:'eng-pp-q11',topicId:'eng-poetry-power',question:'What is a dramatic monologue?',options:['A poem read aloud on stage','A poem in which a single speaker addresses a silent listener, revealing aspects of their character and situation through their words','A monologue in a play','A poem with no speaker'],correctAnswer:1,explanation:'A dramatic monologue features a single speaker addressing an implied listener. What the speaker reveals (intentionally and unintentionally) about their character, attitudes and situation is key to the poem\'s meaning and effect.',difficulty:'foundation'},
           {id:'eng-pp-q12',topicId:'eng-poetry-power',question:'A poem about nature uses personification to describe a storm as "angry" and "vengeful." How does this relate to themes of power?',options:['It does not relate to power','It presents nature as a powerful, almost sentient force that acts with intention, suggesting nature\'s power is greater than or indifferent to human control','Personification is only used in stories','Storms are not related to power'],correctAnswer:1,explanation:'Personifying nature as having human emotions and intentions emphasises its power and autonomy. Describing a storm as "angry" suggests a force that acts with purpose, reinforcing themes about nature\'s supremacy over human power.',difficulty:'higher'},
           {id:'eng-pp-q13',topicId:'eng-poetry-power',question:'Why might a poet choose free verse (no regular metre or rhyme) for a poem about conflict?',options:['They could not think of any rhymes','Free verse can mirror the unpredictability and chaos of conflict, rejecting the order that traditional forms impose','Free verse is always better','All conflict poems must use free verse'],correctAnswer:1,explanation:'Free verse rejects the constraints of regular metre and rhyme, which can mirror the chaos, unpredictability and lack of control experienced in conflict. The absence of pattern reflects the disruption that conflict causes.',difficulty:'intermediate'},
           {id:'eng-pp-q14',topicId:'eng-poetry-power',question:'What is the significance of a poet choosing to write in the present tense about a past event?',options:['It is a grammatical mistake','It creates immediacy, making past events feel as though they are happening now and drawing the reader into the experience','Present tense is easier to write','It means the events are fictional'],correctAnswer:1,explanation:'Using present tense for past events creates immediacy and urgency. It suggests the experiences are still vivid and present in the speaker\'s mind, which is particularly powerful in poems about trauma, memory and the lasting effects of conflict.',difficulty:'intermediate'},
           {id:'eng-pp-q15',topicId:'eng-poetry-power',question:'How should you approach analysing an unfamiliar poem that appears alongside a named poem in the exam?',options:['Panic because you have not seen it before','There is no unseen poem in the Power and Conflict section; you choose from the anthology, but you should be confident comparing any two poems by identifying shared themes, contrasting methods and linking to context','Only write about the named poem','Memorise all possible poems'],correctAnswer:1,explanation:'In the AQA exam, you choose your comparison poem from the anthology. You should practise comparing poems across different theme pairings so you can confidently select the best match and write an integrated comparison.',difficulty:'further'}]),
        t('eng-poetry-comparison', 'eng-poetry', 'Comparing Poems', 'Methods of comparison, linking themes and structural analysis across poems.',
          'The AQA Literature exam requires you to compare a named poem with one you choose from the anthology. Your comparison must address both poems\' methods and their thematic connections. The key to a successful comparison is selecting a poem that offers meaningful similarities and differences with the named poem, allowing you to develop a nuanced argument.\n\nEffective comparison moves between poems rather than treating them separately. Use comparative connectives such as "similarly", "in contrast", "whereas", "both poets" and "however" to make explicit links. Each paragraph should ideally reference both poems, comparing a specific aspect such as how each poet uses imagery to present power, or how structural choices reflect different attitudes to conflict.\n\nWhen comparing, consider: the poets\' different perspectives on the same theme; similarities and differences in their use of form and structure; contrasting tones and how these reflect attitudes; the effect of different narrative voices or viewpoints; and how context might explain differences in approach. A sophisticated comparison will identify both similarities and differences, rather than focusing on only one. End your response with a conclusion that summarises the key comparison and offers a final evaluative comment on how the poets\' approaches differ or align.',
          ['Compare by moving between poems, not writing about each separately', 'Use comparative connectives: similarly, in contrast, whereas, however, both poets', 'Compare methods (language, structure, form) as well as themes', 'Consider how context explains different approaches to the same theme', 'Choose a comparison poem that allows you to explore meaningful similarities and differences'],
          [{id:'ef28',front:'What is the key to an effective poetry comparison?',back:'Moving between poems in each paragraph using comparative connectives, comparing specific methods and themes rather than treating each poem separately.'},{id:'ef29',front:'What should you consider when choosing a comparison poem?',back:'Choose a poem with meaningful thematic connections that offers both similarities and differences, allowing you to develop a nuanced argument about how different poets approach the same ideas.'},{id:'ef30',front:'Name four comparative connectives for poetry comparison.',back:'Similarly, in contrast, whereas, however. Also: both poets, unlike, on the other hand, conversely.'}],
          [{id:'eng-pc-q1',topicId:'eng-poetry-comparison',question:'Which approach to comparing poems is most likely to achieve higher marks?',options:['Writing about Poem A in full, then Poem B in full','Comparing one technique from each poem per paragraph, moving between texts','Only discussing the poem you know better','Listing all the techniques in both poems without comparison'],correctAnswer:1,explanation:'An integrated comparison that moves between poems within each paragraph is the most effective approach. Each paragraph should compare a specific method or theme across both poems using comparative connectives.',difficulty:'intermediate'},
           {id:'eng-pc-q2',topicId:'eng-poetry-comparison',question:'Why is it important to compare methods as well as themes?',options:['It is not important - themes are enough','Comparing methods shows how poets use language, structure and form differently to present similar or contrasting ideas, demonstrating deeper analysis','Methods are easier to write about than themes','The exam only asks about methods, not themes'],correctAnswer:1,explanation:'Comparing methods shows a deeper level of analysis. It is not enough to say two poems are both about power; you must explain how each poet uses language, structure and form to convey their particular perspective on power.',difficulty:'higher'},
           {id:'eng-pc-q3',topicId:'eng-poetry-comparison',question:'What makes a good choice of comparison poem?',options:['The poem you have memorised the most quotations from','A poem that shares the same theme but approaches it from a different perspective, allowing exploration of both similarities and differences','The shortest poem in the anthology','A poem on a completely different theme'],correctAnswer:1,explanation:'The best comparison poems share thematic connections but offer different perspectives or methods. This allows you to explore meaningful similarities and differences, leading to a nuanced and sophisticated argument.',difficulty:'intermediate'},
           {id:'eng-pc-q4',topicId:'eng-poetry-comparison',question:'What are comparative connectives and why are they important?',options:['Words that connect poems physically','Words and phrases like "similarly", "however", "in contrast" and "whereas" that explicitly link your discussion of two poems','Connectives are not needed in poetry essays','Words that describe poems'],correctAnswer:1,explanation:'Comparative connectives signal to the reader (and examiner) that you are making direct comparisons. They demonstrate integrated comparison rather than writing about each poem separately, which is essential for higher marks.',difficulty:'foundation'},
           {id:'eng-pc-q5',topicId:'eng-poetry-comparison',question:'A student writes about Poem A for two paragraphs, then about Poem B for two paragraphs. What is the main weakness of this approach?',options:['It is too long','It treats the poems separately rather than comparing them in an integrated way, which limits the depth of comparison','It includes too many quotations','There is nothing wrong with this approach'],correctAnswer:1,explanation:'Writing about each poem separately produces two mini-essays rather than a genuine comparison. The examiner wants to see you move between poems within paragraphs, making explicit comparisons of methods and themes.',difficulty:'intermediate'},
           {id:'eng-pc-q6',topicId:'eng-poetry-comparison',question:'When comparing the form of two poems, what aspects should you consider?',options:['Only whether they rhyme','The type of poem (sonnet, free verse, etc.), stanza structure, rhyme scheme, metre and how these choices relate to meaning','Only the number of lines','Only the font they are printed in'],correctAnswer:1,explanation:'Comparing form involves examining the type of poem, stanza patterns, rhyme scheme, metre and line length. Crucially, you must analyse how these formal choices create different effects and relate to each poem\'s themes and meaning.',difficulty:'intermediate'},
           {id:'eng-pc-q7',topicId:'eng-poetry-comparison',question:'How can you effectively compare the tone of two poems?',options:['Say one is happy and one is sad','Identify and compare the specific attitudes conveyed through word choice, imagery and voice, explaining how different tones reflect different perspectives on the shared theme','Tone is not important in poetry','Use the same tone description for both poems'],correctAnswer:1,explanation:'Tone comparison requires precision. Identify the specific attitudes conveyed (angry, reflective, bitter, nostalgic) and explain how different tones emerge from different word choices, imagery and voice, reflecting contrasting perspectives on the theme.',difficulty:'higher'},
           {id:'eng-pc-q8',topicId:'eng-poetry-comparison',question:'Why might the historical context of two poems be important in a comparison?',options:['Context is never relevant','Different historical contexts can explain why poets approach the same theme differently, enriching your comparison','You should write a history essay instead','Only one poem\'s context matters'],correctAnswer:1,explanation:'Context explains why poets respond differently to similar themes. A Romantic poet may view nature with reverence while a modern poet may see environmental destruction. Linking these differences to historical context adds depth and sophistication to your comparison.',difficulty:'higher'},
           {id:'eng-pc-q9',topicId:'eng-poetry-comparison',question:'What should a strong concluding paragraph in a poetry comparison include?',options:['A completely new point about a third poem','A summary of the key comparison, evaluating how the poets\' different approaches create different effects and which is more impactful','Just the word "conclusion"','A retelling of both poems\' plots'],correctAnswer:1,explanation:'A strong conclusion summarises the key comparison and offers an evaluative comment. It might assess which poet\'s approach is more effective, or reflect on how different methods achieve different but equally powerful effects.',difficulty:'intermediate'},
           {id:'eng-pc-q10',topicId:'eng-poetry-comparison',question:'Two poems both use imagery of nature but one presents it as beautiful and one as destructive. How should you compare them?',options:['Say they are completely different and cannot be compared','Explore how both poets use nature imagery but to contrasting effects, analysing specific language choices that create beauty versus destruction','Only discuss the beautiful poem','Ignore the imagery and focus on rhyme'],correctAnswer:1,explanation:'This is an ideal comparison point. Analyse how specific word choices create contrasting effects: one poet\'s gentle, harmonious language creates beauty, while the other\'s violent, aggressive imagery presents nature as destructive. Link this to their differing perspectives on power.',difficulty:'intermediate'},
           {id:'eng-pc-q11',topicId:'eng-poetry-comparison',question:'What is the benefit of identifying both similarities AND differences in a poetry comparison?',options:['There is no benefit','It creates a more nuanced, sophisticated argument that demonstrates deeper understanding of both poems','You should only discuss differences','You should only discuss similarities'],correctAnswer:1,explanation:'Identifying both similarities and differences shows sophisticated analysis. You might note that both poets explore the same theme but use contrasting methods, or that similar techniques create different effects in different contexts.',difficulty:'foundation'},
           {id:'eng-pc-q12',topicId:'eng-poetry-comparison',question:'How should you use quotations in a poetry comparison?',options:['Include as many as possible without analysis','Use short, embedded quotations from both poems, analysing specific words to support your comparative points','Only quote from one poem','Quotations are not needed in poetry essays'],correctAnswer:1,explanation:'Short, embedded quotations from both poems should be woven into your analytical sentences. Analyse specific word choices and compare how particular words in each poem create different effects, directly supporting your comparative argument.',difficulty:'intermediate'},
           {id:'eng-pc-q13',topicId:'eng-poetry-comparison',question:'A student writes: "Both poems are about power." Why is this an insufficient comparison point?',options:['It is a perfectly good point','It is too vague - you need to specify what aspect of power each poem explores and how the poets\' methods create different presentations of power','Power is not a theme in the anthology','Comparison points should be about structure only'],correctAnswer:1,explanation:'Saying "both poems are about power" is too general. You need to be specific: what type of power? How does each poet present it? What methods do they use? A specific point like "both poets explore the abuse of political power" is more effective.',difficulty:'intermediate'},
           {id:'eng-pc-q14',topicId:'eng-poetry-comparison',question:'When comparing poems, why should you analyse the effect of individual word choices rather than just naming techniques?',options:['Individual words are not important','Analysing specific word choices demonstrates close reading skill and allows you to explain precisely how each poet creates meaning, rather than vaguely naming techniques','Only techniques matter, not individual words','Word choice is only important in prose'],correctAnswer:1,explanation:'Analysing individual word choices shows the examiner that you are engaging closely with the text. Explaining the connotations and effects of specific words is far more impressive than simply labelling techniques without analysis.',difficulty:'higher'},
           {id:'eng-pc-q15',topicId:'eng-poetry-comparison',question:'What is the most common mistake students make in poetry comparison essays?',options:['Using too many quotations','Writing about each poem separately rather than integrating comparison, and retelling the poem\'s content rather than analysing methods','Writing too much','Using comparative connectives'],correctAnswer:1,explanation:'The two most common errors are writing about poems separately (rather than comparing within paragraphs) and describing what happens in the poems rather than analysing how the poets use methods to convey ideas about power and conflict.',difficulty:'further'}]),
      ],
    },
    {
      id: 'eng-modern', subjectId: 'english', name: 'Modern Text',
      topics: [
        t('eng-modern-themes', 'eng-modern', 'Modern Text Themes and Context', 'Social commentary, character development and authorial intent in modern prose and drama.',
          'The AQA GCSE Literature exam includes a question on a modern prose or drama text such as An Inspector Calls, Lord of the Flies, Animal Farm, A Christmas Carol or Blood Brothers. The exam question provides a short extract and asks you to discuss how a theme is presented both in the extract and in the wider text. You must write about the extract in detail and then broaden your discussion to the whole text.\n\nUnderstanding the writer\'s intentions is crucial. Modern texts often contain social commentary: Priestley uses An Inspector Calls to criticise capitalist selfishness and promote collective responsibility; Golding explores the inherent evil in human nature in Lord of the Flies; Orwell satirises totalitarianism in Animal Farm. You must demonstrate awareness of what the writer is suggesting to the audience or reader about society, morality or human nature, using phrases like "Priestley suggests that..." or "Golding implies...".\n\nCharacter development is closely linked to themes. Writers use characters as vehicles for their ideas: characters who change may represent the possibility of redemption or moral growth, while those who remain static may represent entrenched social attitudes. Analyse how writers present characters through dialogue, actions, stage directions (in drama), and other characters\' reactions to them. Consider how characters function symbolically as well as realistically.',
          ['You must discuss both the given extract and the wider text in your response', 'Identify the writer\'s social commentary and authorial intent', 'Use phrases like "the writer suggests/implies/presents" to show awareness of craft', 'Analyse character development as a vehicle for the writer\'s themes', 'Consider characters both realistically and symbolically'],
          [{id:'ef31',front:'What does the modern text exam question require?',back:'Discuss how a theme is presented in a given extract AND in the wider text. You must analyse the extract in detail and then broaden your discussion to include other relevant parts of the text.'},{id:'ef32',front:'Why is authorial intent important in a literature essay?',back:'Demonstrating awareness of the writer\'s purpose shows higher-level analysis. Use phrases like "the writer suggests" or "Priestley implies" to show you understand the text as a deliberate construct with a message.'},{id:'ef33',front:'How should you analyse character development?',back:'Consider how characters change or remain static, what they represent thematically, and how the writer presents them through dialogue, actions, stage directions, and other characters\' responses.'}],
          [{id:'eng-md-q1',topicId:'eng-modern-themes',question:'In a literature essay on a modern text, what should you demonstrate alongside close textual analysis?',options:['Knowledge of the author\'s personal life','Awareness of the writer\'s intentions and what they are suggesting about society, morality or human nature','Memorisation of every quotation in the text','A summary of the entire plot from start to finish'],correctAnswer:1,explanation:'Higher-level responses demonstrate awareness of authorial intent: what the writer is suggesting to their audience about society, morality or human nature. This shows you understand the text as a deliberate construct with a purpose.',difficulty:'intermediate'},
           {id:'eng-md-q2',topicId:'eng-modern-themes',question:'Why might a writer create a character who refuses to change their views throughout a text?',options:['Poor character writing','To represent entrenched social attitudes and suggest that some people resist moral growth or social progress','Because the writer ran out of ideas','To make the plot less interesting'],correctAnswer:1,explanation:'Static characters often represent entrenched attitudes. For example, in An Inspector Calls, Mr Birling\'s refusal to accept responsibility symbolises the stubborn selfishness Priestley saw in the upper classes.',difficulty:'higher'},
           {id:'eng-md-q3',topicId:'eng-modern-themes',question:'How should you structure a modern text essay in the AQA exam?',options:['Write only about the extract given','Write only about the wider text, ignoring the extract','Analyse the extract in detail first, then broaden your discussion to the wider text, linking both to the theme','Retell the plot of the whole text'],correctAnswer:2,explanation:'The exam requires you to discuss the theme in both the extract and the wider text. Start with close analysis of the extract, then broaden your discussion to show how the theme is developed across the whole text.',difficulty:'intermediate'},
           {id:'eng-md-q4',topicId:'eng-modern-themes',question:'What does the phrase "the writer presents" signal in a literature essay?',options:['That you are summarising the plot','That you understand the text is a deliberate construct and you are analysing the writer\'s craft','That you are quoting directly from the text','That you disagree with the writer'],correctAnswer:1,explanation:'Using phrases like "the writer presents/suggests/implies" shows awareness that the text is a crafted piece of writing with deliberate choices. This is a key feature of higher-level analysis.',difficulty:'foundation'},
           {id:'eng-md-q5',topicId:'eng-modern-themes',question:'A character in a modern text undergoes a moral transformation. This most likely represents:',options:['A plot hole','The possibility of redemption or moral growth, reflecting the writer\'s belief that change is possible','Poor character development','An unrealistic plot device'],correctAnswer:1,explanation:'Writers often use character development to convey thematic ideas. A character who changes represents the possibility of moral growth and is used to suggest that people can learn and improve.',difficulty:'intermediate'},
           {id:'eng-md-q6',topicId:'eng-modern-themes',question:'In a drama text, stage directions are important to analyse because they:',options:['Tell the actors where to stand','Reveal the writer\'s intentions about character, mood and meaning through non-verbal communication','Are not relevant to the exam','Only describe the set design'],correctAnswer:1,explanation:'Stage directions reveal the writer\'s intentions about how characters should behave, their emotional states, and the atmosphere. Analysing them shows understanding of dramatic craft.',difficulty:'intermediate'},
           {id:'eng-md-q7',topicId:'eng-modern-themes',question:'When discussing social commentary in a modern text, you should:',options:['Only describe the historical context','Explain what the writer is criticising or promoting about society and how they use characters and events to do so','Ignore the social context entirely','Focus only on the language used'],correctAnswer:1,explanation:'Social commentary analysis requires you to explain what message the writer conveys about society, and how they use characters, plot and language as vehicles for their ideas.',difficulty:'higher'},
           {id:'eng-md-q8',topicId:'eng-modern-themes',question:'Why might a writer use a character as a symbol?',options:['To make the character more realistic','To represent an abstract idea or social group, adding layers of meaning beyond the literal narrative','Symbols are only used in poetry','To confuse the reader'],correctAnswer:1,explanation:'Symbolic characters represent abstract concepts (e.g., greed, innocence, social class). This allows the writer to explore ideas through character interactions and development.',difficulty:'higher'},
           {id:'eng-md-q9',topicId:'eng-modern-themes',question:'What is the difference between theme and plot?',options:['They are the same thing','Plot is what happens in the story; theme is the underlying idea or message the writer explores','Theme is the genre of the text','Plot only applies to novels, not plays'],correctAnswer:1,explanation:'Plot refers to the sequence of events. Theme is the deeper idea or message the writer explores through those events (e.g., justice, responsibility, power, morality).',difficulty:'foundation'},
           {id:'eng-md-q10',topicId:'eng-modern-themes',question:'When analysing dialogue in a modern text, you should consider:',options:['Only the literal meaning of the words','What the dialogue reveals about the character, their relationships, and the writer\'s thematic intentions','Whether the dialogue is grammatically correct','How many lines each character speaks'],correctAnswer:1,explanation:'Dialogue reveals character traits, power dynamics, relationships, and can convey the writer\'s themes. Consider not just what characters say but how they say it and what is left unsaid.',difficulty:'intermediate'},
           {id:'eng-md-q11',topicId:'eng-modern-themes',question:'How do other characters\' reactions help to present a central character?',options:['They do not — only the central character\'s own words matter','Reactions reveal how the character is perceived, highlighting their impact on others and reinforcing or challenging themes','Other characters are not important in modern texts','Only the narrator\'s reaction matters'],correctAnswer:1,explanation:'How other characters respond to a central character reveals their status, influence and moral position. This is a deliberate technique writers use to shape the reader\'s or audience\'s understanding.',difficulty:'higher'},
           {id:'eng-md-q12',topicId:'eng-modern-themes',question:'Which of the following would be the weakest opening to a modern text essay paragraph?',options:['"Priestley uses the Inspector as a mouthpiece to challenge capitalist attitudes."','"In this extract, the writer presents the theme of responsibility through..."','"The text is about a family who get visited by an inspector."','"The writer implies that society\'s refusal to accept collective responsibility is dangerous."'],correctAnswer:2,explanation:'Option three is a plot summary rather than an analytical point. Strong paragraphs open with an analytical statement about the writer\'s methods, intentions or thematic ideas, not a retelling of events.',difficulty:'intermediate'},
           {id:'eng-md-q13',topicId:'eng-modern-themes',question:'The ending of a modern text is particularly important to analyse because:',options:['It is the last thing the examiner reads','The writer uses it to leave the reader with a final message or question about the themes explored','Endings are always happy','The ending is always surprising'],correctAnswer:1,explanation:'The ending is where the writer delivers their final statement on the themes. Whether it offers resolution or remains ambiguous, it is a deliberate choice that reinforces the writer\'s message.',difficulty:'intermediate'},
           {id:'eng-md-q14',topicId:'eng-modern-themes',question:'Context in a modern text essay should be used to:',options:['Fill up space when you run out of analysis','Explain how the social or historical context influenced the writer\'s message and enhances the reader\'s understanding','Replace close analysis of the text','Show off your knowledge of history'],correctAnswer:1,explanation:'Context should be woven into analysis to explain why the writer wrote as they did and what influenced their message. It should enhance your analytical points, not replace them.',difficulty:'further'}]),
      ],
    },
    {
      id: 'eng-writing', subjectId: 'english', name: 'Writing Skills',
      topics: [
        t('eng-writing-techniques', 'eng-writing', 'Writing Techniques', 'Figurative language, rhetorical devices, sentence structures and paragraphing.',
          'Effective writing at GCSE level requires a repertoire of techniques deployed with precision. Figurative language creates vivid imagery and deepens meaning: similes compare using "like" or "as", metaphors state that something is something else, and personification gives human qualities to non-human things. Extended metaphors sustained across a passage can create a powerful thematic thread. Hyperbole exaggerates for effect, while understatement creates dry or ironic tones.\n\nRhetorical devices are particularly important for persuasive writing. Rhetorical questions engage the reader by prompting them to consider an answer. The rule of three (tricolon) creates rhythm and emphasis. Anaphora (repeating a word or phrase at the start of successive sentences) builds momentum. Direct address using "you" and "we" creates a sense of shared experience. Antithesis places contrasting ideas together for dramatic effect.\n\nSentence structure variety is essential for high marks. Short, simple sentences create impact, tension or emphasis. Compound sentences link related ideas. Complex sentences with subordinate clauses show sophistication and allow you to add layers of detail. One-word or one-line paragraphs can be used for dramatic effect. Vary your paragraph lengths and use discourse markers to guide the reader through your text.',
          ['Figurative language: similes, metaphors, personification, hyperbole', 'Rhetorical devices: rhetorical questions, rule of three, anaphora, direct address, antithesis', 'Vary sentence structures: short for impact, complex for sophistication', 'One-sentence paragraphs can create dramatic emphasis', 'Discourse markers guide the reader through your argument or narrative'],
          [{id:'ef34',front:'What is anaphora?',back:'The deliberate repetition of a word or phrase at the beginning of successive clauses or sentences, used to build rhythm, emphasis and momentum.'},{id:'ef35',front:'Why is sentence structure variety important?',back:'It keeps the reader engaged and shows conscious craftsmanship. Short sentences create impact; complex sentences add sophistication and detail. Varying structure demonstrates control of writing.'},{id:'ef36',front:'What is antithesis?',back:'Placing two contrasting ideas in close proximity for dramatic effect, such as "It was the best of times, it was the worst of times." It highlights differences and creates memorable phrasing.'}],
          [{id:'eng-wt-q1',topicId:'eng-writing-techniques',question:'Which of the following sentences uses a metaphor?',options:['"The wind howled like a wolf through the valley."','"The classroom was a zoo, with students swinging from desk to desk."','"She ran quickly towards the finish line."','"The sunset was beautiful and orange."'],correctAnswer:1,explanation:'A metaphor states that something IS something else, unlike a simile which uses "like" or "as". Calling the classroom a "zoo" is a metaphor. The first option is a simile because it uses "like".',difficulty:'intermediate'},
           {id:'eng-wt-q2',topicId:'eng-writing-techniques',question:'A student writes three consecutive sentences beginning with "We must act." What technique is this, and what effect does it create?',options:['Alliteration - it creates a pleasing sound','Anaphora - the repetition builds momentum, urgency and emphasis','Onomatopoeia - it imitates the sound of action','Enjambment - it creates flow between lines'],correctAnswer:1,explanation:'Anaphora is the deliberate repetition of a word or phrase at the start of successive sentences or clauses. Here, the repetition of "We must act" builds urgency, momentum and rhetorical power.',difficulty:'higher'},
           {id:'eng-wt-q3',topicId:'eng-writing-techniques',question:'Why might a writer use a one-sentence paragraph?',options:['Because they could not think of anything else to write','To create dramatic emphasis, shock, or a moment of pause for the reader','Because paragraphs should always be one sentence long','To save space on the page'],correctAnswer:1,explanation:'One-sentence paragraphs are a deliberate structural choice. The white space around them draws the reader\'s attention, creating dramatic emphasis, a moment of pause, or highlighting a key idea.',difficulty:'intermediate'},
           {id:'eng-wt-q4',topicId:'eng-writing-techniques',question:'What is the "rule of three" (tricolon)?',options:['A poem with three stanzas','Using three examples, adjectives or phrases together for rhythm and emphasis','Writing in three paragraphs','Using three full stops in a row'],correctAnswer:1,explanation:'The rule of three groups ideas, words or phrases in threes for rhetorical impact. It creates rhythm and makes ideas more memorable, e.g., "government of the people, by the people, for the people."',difficulty:'foundation'},
           {id:'eng-wt-q5',topicId:'eng-writing-techniques',question:'What is personification?',options:['Using "like" or "as" to compare two things','Giving human qualities or actions to non-human things','Exaggerating for effect','Repeating the same consonant sound'],correctAnswer:1,explanation:'Personification attributes human qualities, feelings or actions to non-human things, e.g., "the wind whispered through the trees." It brings descriptions to life and creates atmosphere.',difficulty:'foundation'},
           {id:'eng-wt-q6',topicId:'eng-writing-techniques',question:'A student writes: "Are we truly prepared to let this happen?" This is an example of:',options:['A simile','A rhetorical question','Onomatopoeia','A compound sentence'],correctAnswer:1,explanation:'A rhetorical question is asked for persuasive effect, not to receive an answer. It prompts the reader to reflect and implicitly agree with the writer\'s position.',difficulty:'foundation'},
           {id:'eng-wt-q7',topicId:'eng-writing-techniques',question:'What effect does using direct address ("you") have on the reader?',options:['It makes the text impersonal','It creates a sense of connection and makes the reader feel personally involved','It weakens the argument','It is only used in letters'],correctAnswer:1,explanation:'Direct address using "you" and "we" draws the reader in, creating a sense of shared experience, involvement, and personal responsibility. It is particularly effective in persuasive writing.',difficulty:'intermediate'},
           {id:'eng-wt-q8',topicId:'eng-writing-techniques',question:'An extended metaphor is:',options:['A very long sentence','A metaphor sustained over several sentences or across a whole text, developing a single comparison','A metaphor using the word "like"','A type of simile'],correctAnswer:1,explanation:'An extended metaphor develops a single comparison across multiple sentences, lines or even an entire text, creating a sustained thematic thread and deeper layer of meaning.',difficulty:'higher'},
           {id:'eng-wt-q9',topicId:'eng-writing-techniques',question:'Short, simple sentences are most effective when used to:',options:['Show off vocabulary','Create impact, tension, emphasis or a sudden change of pace','Fill space in an essay','Avoid making grammatical errors'],correctAnswer:1,explanation:'Short sentences create punch and impact. After longer, complex sentences they can create a dramatic shift in pace. They are particularly effective at moments of tension, shock or emphasis.',difficulty:'intermediate'},
           {id:'eng-wt-q10',topicId:'eng-writing-techniques',question:'What is antithesis?',options:['Repeating the first word of successive sentences','Placing two contrasting ideas close together for dramatic effect','Using gentle understatement','An extended simile'],correctAnswer:1,explanation:'Antithesis juxtaposes opposing ideas in close proximity to highlight contrast and create memorable, balanced phrasing. It is particularly effective in speeches and persuasive writing.',difficulty:'higher'},
           {id:'eng-wt-q11',topicId:'eng-writing-techniques',question:'Discourse markers such as "However", "Furthermore" and "Consequently" are used to:',options:['Make writing sound more formal only','Guide the reader through the argument or narrative, showing how ideas connect','Replace full stops','Begin every paragraph'],correctAnswer:1,explanation:'Discourse markers are cohesive devices that signal the relationship between ideas: contrast (However), addition (Furthermore), cause and effect (Consequently). They help the reader follow the argument.',difficulty:'intermediate'},
           {id:'eng-wt-q12',topicId:'eng-writing-techniques',question:'What is hyperbole?',options:['A type of rhyme','Deliberate exaggeration for emphasis or effect, not meant to be taken literally','A gentle understatement','A factual description'],correctAnswer:1,explanation:'Hyperbole is intentional exaggeration used for emphasis, humour, or persuasive effect. For example, "I have told you a million times" is not literal but stresses the frequency.',difficulty:'foundation'},
           {id:'eng-wt-q13',topicId:'eng-writing-techniques',question:'A complex sentence contains:',options:['Only one clause','Two independent clauses joined by a conjunction','A main clause and at least one subordinate clause','No verbs'],correctAnswer:2,explanation:'A complex sentence has a main (independent) clause and at least one subordinate (dependent) clause. This allows writers to add layers of detail, qualification, and sophistication.',difficulty:'intermediate'},
           {id:'eng-wt-q14',topicId:'eng-writing-techniques',question:'Why is varying sentence length important in effective writing?',options:['It is not important — all sentences should be the same length','It creates rhythm, controls pace and keeps the reader engaged','It shows you know different sentence types','Examiners count sentence length for marks'],correctAnswer:1,explanation:'Varying sentence length creates rhythm and controls pace. Long sentences build detail and atmosphere; short ones create impact. The contrast between them keeps the reader engaged and demonstrates craft.',difficulty:'higher'}]),
        t('eng-writing-accuracy', 'eng-writing', 'SPaG and Accuracy', 'Spelling, punctuation, grammar and ambitious vocabulary for high marks.',
          'Technical accuracy in spelling, punctuation and grammar (SPaG) is worth a significant proportion of marks on both English Language papers. On Paper 1 and Paper 2, 16 out of 40 marks for the writing section are awarded for technical accuracy. This means that even a brilliantly creative or persuasive piece will not achieve top marks if it is riddled with errors.\n\nPunctuation must be varied and accurate. Full stops, commas and capital letters should be consistently correct. Higher-level punctuation includes semicolons (linking two closely related independent clauses), colons (introducing an explanation, list or elaboration), dashes (for parenthetical information or dramatic emphasis), and ellipsis (to create suspense or trail off). Apostrophes must be used correctly for possession (the dog\'s bone) and contraction (don\'t), but never for plurals.\n\nSpelling should be accurate, particularly for common words and subject-specific terminology. Ambitious vocabulary means choosing precise, sophisticated words rather than simple ones: "devastating" rather than "bad", "illuminate" rather than "show". However, accuracy is more important than ambition; using a complex word incorrectly will lose more marks than using a simple word correctly. Grammar should demonstrate variety and control, including correct subject-verb agreement, consistent tense usage, and accurate use of pronouns.',
          ['SPaG is worth 16 of 40 marks on each Language writing section', 'Use varied punctuation: semicolons, colons, dashes, ellipsis, as well as basics', 'Apostrophes for possession and contraction only, never for plurals', 'Choose ambitious but accurate vocabulary - precision matters more than complexity', 'Maintain consistent tense and correct subject-verb agreement'],
          [{id:'ef37',front:'When should you use a semicolon?',back:'To link two closely related independent clauses that could each stand alone as sentences, e.g. "The sky darkened; the storm was approaching."'},{id:'ef38',front:'What is the difference between its and it\'s?',back:'"It\'s" is a contraction of "it is" or "it has". "Its" (no apostrophe) shows possession, e.g. "The dog wagged its tail."'},{id:'ef39',front:'Why is ambitious vocabulary important at GCSE?',back:'It demonstrates a wide range of expression and raises the quality of writing. However, accuracy matters more than ambition: use complex words correctly or choose simpler, precise alternatives.'}],
          [{id:'eng-wa-q1',topicId:'eng-writing-accuracy',question:'Which sentence uses a semicolon correctly?',options:['"I went to the shop; and bought some milk."','"The rain continued to fall; the streets slowly began to flood."','"I like; football, rugby and tennis."','"She was tired; because she had been running."'],correctAnswer:1,explanation:'A semicolon links two closely related independent clauses. In the correct answer, both clauses can stand alone as sentences and are thematically connected. Semicolons should not replace commas or be used before conjunctions.',difficulty:'intermediate'},
           {id:'eng-wa-q2',topicId:'eng-writing-accuracy',question:'Which of the following demonstrates the correct use of an apostrophe?',options:['"The dog\'s were playing in the park."','"Its important to revise regularly."','"The children\'s shoes were muddy."','"The boy\'s went home after school."'],correctAnswer:2,explanation:'"Children\'s" correctly shows possession (the shoes belonging to the children). The other options misuse apostrophes: "dog\'s" and "boy\'s" wrongly use apostrophes for plurals, and "Its" should be "It\'s" (contraction of "it is").',difficulty:'intermediate'},
           {id:'eng-wa-q3',topicId:'eng-writing-accuracy',question:'A student writes: "The man was very bad and did bad things to the bad people." How should this be improved?',options:['Add more adjectives before "bad"','Replace "bad" with varied, precise vocabulary such as "malicious", "heinous" and "vulnerable"','Remove all the adjectives','Use longer sentences to make it sound more academic'],correctAnswer:1,explanation:'Repetition of vague words like "bad" weakens writing. Using varied, precise vocabulary ("malicious", "heinous", "vulnerable") demonstrates range and adds specific meaning. Ambitious vocabulary elevates the quality of expression.',difficulty:'higher'},
           {id:'eng-wa-q4',topicId:'eng-writing-accuracy',question:'How many marks out of 40 are awarded for technical accuracy in the Language paper writing sections?',options:['8 marks','16 marks','24 marks','40 marks'],correctAnswer:1,explanation:'16 out of 40 marks are awarded for technical accuracy (spelling, punctuation and grammar). The other 24 marks are for content and organisation. Accuracy is therefore worth a significant proportion.',difficulty:'foundation'},
           {id:'eng-wa-q5',topicId:'eng-writing-accuracy',question:'Which sentence uses a colon correctly?',options:['"She had: three cats and two dogs."','"There was only one thing left to do: run."','"The weather was: cold and rainy."','"He went to: the shop."'],correctAnswer:1,explanation:'A colon introduces an explanation, elaboration or list that follows from the main clause. "There was only one thing left to do: run" uses it correctly to introduce an explanation.',difficulty:'intermediate'},
           {id:'eng-wa-q6',topicId:'eng-writing-accuracy',question:'When should you use an apostrophe in "its"?',options:['Always, because it shows possession','Never — "its" (no apostrophe) shows possession; "it\'s" is a contraction of "it is"','Only in formal writing','When referring to animals'],correctAnswer:1,explanation:'"Its" without an apostrophe shows possession (e.g., "the dog wagged its tail"). "It\'s" with an apostrophe is a contraction of "it is" or "it has". This is one of the most common errors.',difficulty:'intermediate'},
           {id:'eng-wa-q7',topicId:'eng-writing-accuracy',question:'What is the purpose of an ellipsis (...) in creative writing?',options:['To show a spelling mistake','To create suspense, suggest a trailing off or leave something unsaid','To end every sentence','To replace a full stop'],correctAnswer:1,explanation:'An ellipsis creates a pause, builds suspense, or suggests a character trailing off or leaving something unsaid. It is a deliberate punctuation choice that controls pace and tone.',difficulty:'intermediate'},
           {id:'eng-wa-q8',topicId:'eng-writing-accuracy',question:'Which of these demonstrates correct subject-verb agreement?',options:['"The group of students were talking loudly."','"The group of students was talking loudly."','"The students was talking loudly."','"The group of students are talks loudly."'],correctAnswer:1,explanation:'"The group" is the subject (singular), so it takes a singular verb "was". The phrase "of students" is a prepositional phrase modifying the subject. Subject-verb agreement requires matching the verb to the actual subject.',difficulty:'higher'},
           {id:'eng-wa-q9',topicId:'eng-writing-accuracy',question:'A dash (—) in writing is used to:',options:['Replace a comma in every situation','Add parenthetical information, create dramatic emphasis, or indicate an abrupt change in thought','Show possession','Mark the end of a sentence'],correctAnswer:1,explanation:'Dashes are versatile punctuation: they can add extra information (like brackets), create emphasis by interrupting the sentence, or signal a sudden shift in direction.',difficulty:'intermediate'},
           {id:'eng-wa-q10',topicId:'eng-writing-accuracy',question:'Why is consistent tense usage important?',options:['It is not important in creative writing','Inconsistent tenses confuse the reader about when events are happening and suggest lack of control','You should always write in past tense','You should always write in present tense'],correctAnswer:1,explanation:'Switching tenses unintentionally confuses the reader and suggests the writer lacks control over their craft. While deliberate tense shifts can be effective, inconsistency loses marks.',difficulty:'intermediate'},
           {id:'eng-wa-q11',topicId:'eng-writing-accuracy',question:'Which is more important for high marks: ambitious vocabulary or accurate vocabulary?',options:['Always use the longest word possible','Accuracy is more important — using a complex word incorrectly loses more marks than using a simple word correctly','Simple vocabulary is always best','Vocabulary does not affect your grade'],correctAnswer:1,explanation:'While ambitious vocabulary is valued, accuracy takes priority. Misusing a sophisticated word undermines the quality of writing more than using a simpler, correctly applied alternative.',difficulty:'higher'},
           {id:'eng-wa-q12',topicId:'eng-writing-accuracy',question:'Where should apostrophes NEVER be used?',options:['In contractions like "don\'t"','In possessives like "the cat\'s whiskers"','In plurals such as "three apple\'s"','After names ending in "s"'],correctAnswer:2,explanation:'Apostrophes should never be used to form plurals. "Three apples" is correct. "Three apple\'s" is a common error known as the greengrocer\'s apostrophe.',difficulty:'foundation'},
           {id:'eng-wa-q13',topicId:'eng-writing-accuracy',question:'A student writes: "Me and my friend went to the park." What is the grammatical error?',options:['There is no error','The subject pronoun should be "I" — "My friend and I went to the park"','It should be "Me and my friends"','"Park" should be capitalised'],correctAnswer:1,explanation:'When used as a subject, the correct pronoun is "I", not "me". "My friend and I" is the grammatically correct form. Placing the other person first is also conventional politeness.',difficulty:'foundation'},
           {id:'eng-wa-q14',topicId:'eng-writing-accuracy',question:'What effect does using a semicolon between two clauses create compared to using a full stop?',options:['No difference','It signals a closer connection between the two ideas while maintaining their independence','It makes the writing more informal','It creates a longer pause than a full stop'],correctAnswer:1,explanation:'A semicolon links two independent clauses that are closely related in meaning, suggesting a stronger connection between the ideas than a full stop would. It demonstrates sophisticated punctuation control.',difficulty:'higher'}]),
      ],
    },
    {
      id: 'eng-reading', subjectId: 'english', name: 'Reading Skills',
      topics: [
        t('eng-reading-analysis', 'eng-reading', 'Analytical Reading Skills', 'Inference, deduction, PEE/PEEL paragraphs and embedding quotations.',
          'Analytical reading is the foundation of success in both English Language and Literature. Inference means reading beyond the literal meaning to understand what is implied or suggested. When a writer describes a character "clutching the letter with trembling hands", the inference is that the character is anxious, frightened or overcome with emotion. Strong inference goes further to consider why the writer made this choice and what it reveals about character, theme or atmosphere.\n\nThe PEE (Point, Evidence, Explain) paragraph structure is the basic framework for analytical writing, but PEEL (Point, Evidence, Explain, Link) is more effective at higher levels. Make a clear point that directly addresses the question. Support it with a short, embedded quotation rather than a long, standalone quote. Explain the effect of specific words within the quotation, analysing connotations and techniques. Finally, link back to the question or forward to your next point to maintain a coherent argument.\n\nEmbedding quotations means weaving them into your own sentences rather than placing them as separate blocks. For example, instead of writing \'The writer says: "The room was dark and cold."\', write \'The writer\'s description of the "dark and cold" room creates an oppressive atmosphere.\' Embedded quotations demonstrate confidence and allow you to analyse specific words within their context more naturally.',
          ['Inference: read beyond the literal meaning to understand what is implied', 'PEE/PEEL paragraphs: Point, Evidence, Explain (Link) for structured analysis', 'Embed quotations within your own sentences rather than using standalone quotes', 'Analyse the effect of specific words and their connotations', 'Always link your analysis back to the question being asked'],
          [{id:'ef40',front:'What is the difference between inference and deduction?',back:'Inference is reading between the lines to understand what is implied. Deduction is drawing logical conclusions based on the evidence presented. Both require looking beyond the literal meaning.'},{id:'ef41',front:'What does PEEL stand for?',back:'Point (a clear analytical statement), Evidence (a short embedded quotation), Explain (analyse the effect of specific words), Link (connect back to the question or forward to your next point).'},{id:'ef42',front:'How should quotations be embedded?',back:'Weave them into your own sentences. Instead of \'The writer says: "dark and cold"\', write: \'The "dark and cold" setting creates an oppressive atmosphere.\' This is more fluent and sophisticated.'}],
          [{id:'eng-ra-q1',topicId:'eng-reading-analysis',question:'A writer describes a character who "straightened his tie and practised his smile in the mirror." What can be inferred?',options:['The character is vain and obsessed with appearance','The character is preparing to present a false image of confidence or friendliness','The character enjoys fashion','Nothing can be inferred from this description'],correctAnswer:1,explanation:'The inference is that the character is preparing to present a version of himself that differs from how he truly feels. "Practised his smile" suggests the smile is not genuine, implying anxiety, dishonesty or a desire to maintain appearances.',difficulty:'intermediate'},
           {id:'eng-ra-q2',topicId:'eng-reading-analysis',question:'Which of the following best demonstrates an embedded quotation?',options:['"The writer says: The sky was blood-red."','The writer describes the sky. "It was blood-red."','The "blood-red" sky suggests violence and foreshadows the conflict to come.','Blood-red is a good description of the sky.'],correctAnswer:2,explanation:'The third option embeds the quotation within the student\'s own analytical sentence, analyses the connotations of "blood-red" (violence), and links to the text\'s themes (foreshadowing conflict). This is sophisticated analytical writing.',difficulty:'higher'},
           {id:'eng-ra-q3',topicId:'eng-reading-analysis',question:'What is the main weakness of the following analysis? "The writer uses a simile. This is effective because it helps the reader imagine the scene."',options:['It is too long','It does not identify the specific simile, explain what it compares, or analyse the effect of particular word choices','It uses incorrect terminology','It includes too many quotations'],correctAnswer:1,explanation:'The analysis is vague: it identifies the technique but does not quote it, explain the comparison, or analyse specific word choices. Effective analysis must be specific, quoting the exact language and explaining the connotations and effects of individual words.',difficulty:'intermediate'},
           {id:'eng-ra-q4',topicId:'eng-reading-analysis',question:'What does inference mean in reading?',options:['Reading beyond the literal meaning to understand what is implied','Copying words from the text','Summarising the plot','Identifying sentence types'],correctAnswer:0,explanation:'Inference means reading between the lines to understand what the writer suggests or implies, rather than what is explicitly stated.',difficulty:'foundation'},
           {id:'eng-ra-q5',topicId:'eng-reading-analysis',question:'What does PEEL stand for?',options:['Point, Evidence, Explain, Link','Point, Example, Evaluate, Learn','Paragraph, Evidence, Example, List','Point, Evidence, Examine, Locate'],correctAnswer:0,explanation:'PEEL: Point (clear statement), Evidence (quotation), Explain (analyse effect), Link (connect to question or next point).',difficulty:'foundation'},
           {id:'eng-ra-q6',topicId:'eng-reading-analysis',question:'Why is it better to embed quotations rather than use standalone quotes?',options:['It shows greater confidence and allows analysis of words within context','It makes the essay longer','It avoids plagiarism','Standalone quotes are never correct'],correctAnswer:0,explanation:'Embedding quotations in your own sentences demonstrates fluency and sophistication, and allows you to analyse specific words more naturally.',difficulty:'intermediate'},
           {id:'eng-ra-q7',topicId:'eng-reading-analysis',question:'A character is described as having "eyes like a hawk." What technique is this?',options:['Simile','Metaphor','Alliteration','Personification'],correctAnswer:0,explanation:'This is a simile — a comparison using "like" or "as." It suggests the character is sharp-eyed and observant.',difficulty:'foundation'},
           {id:'eng-ra-q8',topicId:'eng-reading-analysis',question:'What are connotations?',options:['The ideas and feelings associated with a word beyond its literal meaning','The dictionary definition of a word','Grammar rules','Sentence structures'],correctAnswer:0,explanation:'Connotations are the associations, ideas, or feelings a word carries beyond its literal (denotative) meaning. Analysing connotations is key to effective language analysis.',difficulty:'intermediate'},
           {id:'eng-ra-q9',topicId:'eng-reading-analysis',question:'The word "crimson" is used instead of "red." Why might a writer make this choice?',options:['Crimson has connotations of blood, violence and intensity that "red" lacks','Crimson is a longer word','There is no difference','Crimson sounds more modern'],correctAnswer:0,explanation:'"Crimson" carries stronger connotations of blood, danger and intensity than the more neutral word "red," creating a more vivid and emotionally charged image.',difficulty:'intermediate'},
           {id:'eng-ra-q10',topicId:'eng-reading-analysis',question:'What is the difference between analysis and feature-spotting?',options:['Analysis explains the effect of language choices; feature-spotting merely identifies techniques','They are the same thing','Feature-spotting is more detailed','Analysis only applies to poetry'],correctAnswer:0,explanation:'Feature-spotting identifies techniques (e.g. "this is a metaphor") without explaining their effect. Analysis goes further to explain why the writer used the technique and what impact it has on the reader.',difficulty:'intermediate'},
           {id:'eng-ra-q11',topicId:'eng-reading-analysis',question:'A writer uses short, one-word sentences during a chase scene. What effect does this create?',options:['It mirrors the breathless pace and builds tension','It shows the writer has a limited vocabulary','It makes the writing easier to read','It has no particular effect'],correctAnswer:0,explanation:'Short sentences create a fast pace that mirrors the action. They also create tension by giving each word emphasis and making the reader feel the urgency of the scene.',difficulty:'intermediate'},
           {id:'eng-ra-q12',topicId:'eng-reading-analysis',question:'Which of these is the strongest analytical statement?',options:['"The writer uses adjectives"','"The adjective dark creates a threatening atmosphere, suggesting danger lurks unseen"','"Dark is a good word choice"','"The writer uses lots of describing words throughout"'],correctAnswer:1,explanation:'The second option identifies the specific word, names the effect (threatening atmosphere), and explains what it suggests. This is precise, detailed analysis.',difficulty:'higher'},
           {id:'eng-ra-q13',topicId:'eng-reading-analysis',question:'What does it mean to "zoom in" on language?',options:['Analyse individual words and their effects','Read the text from far away','Skip to the end of the text','Only read the title'],correctAnswer:0,explanation:'Zooming in means focusing on individual words within a quotation, analysing their connotations, sounds, and effects rather than commenting on the quotation as a whole.',difficulty:'intermediate'},
           {id:'eng-ra-q14',topicId:'eng-reading-analysis',question:'A writer describes a room as "tomb-like." What technique is this and what does it suggest?',options:['Simile; the room is lively and welcoming','Metaphor; the room is cold, dark and possibly associated with death','Onomatopoeia; the room makes noise','Hyperbole; the room is quite small'],correctAnswer:1,explanation:'"Tomb-like" is a metaphor/simile comparing the room to a tomb, suggesting it is cold, dark, lifeless and associated with death. It creates an oppressive, threatening atmosphere.',difficulty:'higher'},
           {id:'eng-ra-q15',topicId:'eng-reading-analysis',question:'Why should you avoid starting analytical paragraphs with "The writer uses..."?',options:['It makes essays too long','It leads to feature-spotting rather than analysis; it is better to start with the effect or idea','It is grammatically incorrect','You should always start with this phrase'],correctAnswer:1,explanation:'Starting with "The writer uses..." often leads to technique identification without analysis. Starting with the effect or idea (e.g. "A sense of unease is created through...") produces more analytical writing.',difficulty:'higher'}]),
        t('eng-reading-evaluation', 'eng-reading', 'Evaluation and Comparison', 'Critical evaluation, synthesising information and comparing texts.',
          'Critical evaluation requires you to make a judgement about a text and support it with evidence. In English Language Paper 1 Q4, you are given a statement about the text and asked to what extent you agree. Your response should present a clear viewpoint, supported by evidence from the text and analysis of the writer\'s methods. You might agree, disagree, or partially agree, but your position must be consistent and well-argued throughout.\n\nSynthesising information is a key skill for Paper 2, where you must draw together ideas from two texts. Rather than simply summarising each text separately, synthesis requires you to identify connections and differences. Use the texts together to build a coherent understanding of a topic or theme. This means making inferences from both texts and comparing what they reveal, rather than treating them in isolation.\n\nComparing texts requires you to consider not just what the texts say but how they say it. Compare the writers\' methods: their use of language, structural choices, tone, and the effects these create. Consider how the texts\' different contexts (time period, audience, purpose) influence the writers\' approaches. Strong comparisons identify both similarities and differences and explain why these exist, referring to context where relevant.',
          ['Critical evaluation: take a clear position and sustain it with evidence and analysis', 'Synthesise by drawing together ideas from multiple texts, not summarising separately', 'Compare methods (how) as well as content (what)', 'Consider how context influences different writers\' approaches', 'Use comparative connectives to link your points across texts'],
          [{id:'ef43',front:'What does "to what extent do you agree" mean in an evaluation question?',back:'You must decide how far you agree with the given statement and sustain your position throughout. You can fully agree, partially agree, or disagree, but must support your view with evidence and analysis.'},{id:'ef44',front:'What is the difference between summarising and synthesising?',back:'Summarising restates what each text says individually. Synthesising draws together information from both texts to build a connected understanding, identifying patterns and making comparisons.'},{id:'ef45',front:'Why should you compare methods as well as content?',back:'Comparing methods shows deeper analysis by examining HOW writers convey their ideas, not just WHAT they say. This includes language choices, structural decisions, tone and the effects these create.'}],
          [{id:'eng-re-q1',topicId:'eng-reading-evaluation',question:'A Paper 1 Q4 statement says: "The writer successfully creates a sense of danger." Which response opening is most effective?',options:['"I agree with this statement."','"The writer does create danger because scary things happen."','"The writer creates a palpable sense of danger through a combination of foreboding imagery and relentlessly short, fragmented sentences that mirror the character\'s rising panic."','"The question asks if the writer creates danger. I will now discuss this."'],correctAnswer:2,explanation:'The third option immediately presents a clear, specific argument with reference to particular methods (imagery and sentence structure) and their effects. It demonstrates confident, evaluative writing from the very first sentence.',difficulty:'higher'},
           {id:'eng-re-q2',topicId:'eng-reading-evaluation',question:'What is the key difference between synthesis and summary?',options:['There is no difference','Summary restates information from one text; synthesis draws together information from multiple texts to identify connections and comparisons','Summary is more detailed than synthesis','Synthesis only works with fiction texts'],correctAnswer:1,explanation:'Summary simply restates what a text says. Synthesis is more sophisticated: it combines information from multiple sources, identifying connections, patterns and differences to build a richer understanding.',difficulty:'intermediate'},
           {id:'eng-re-q3',topicId:'eng-reading-evaluation',question:'When comparing two non-fiction texts, why is it important to consider context?',options:['It is not important','Because context explains why writers from different time periods may approach the same topic differently in terms of language, attitude and conventions','Because you get marks for knowing historical facts','Because one text is always better than the other'],correctAnswer:1,explanation:'Context helps explain differences in language, attitude and method. A 19th-century writer may use more formal language and different conventions than a modern writer. Understanding this allows deeper, more nuanced comparison.',difficulty:'higher'},
           {id:'eng-re-q4',topicId:'eng-reading-evaluation',question:'What does "to what extent do you agree" require you to do?',options:['Simply say yes or no','Take a clear position and sustain it with evidence and analysis throughout','Copy the statement','Ignore the statement and write about something else'],correctAnswer:1,explanation:'You must decide how far you agree with the statement and maintain your position consistently, supporting it with evidence and analysis of the writer\'s methods.',difficulty:'foundation'},
           {id:'eng-re-q5',topicId:'eng-reading-evaluation',question:'What is the difference between summarising and synthesising?',options:['They are the same','Summary restates one text; synthesis draws together multiple texts to identify connections','Synthesis is shorter than summary','Summary is more analytical'],correctAnswer:1,explanation:'Summary restates what a text says. Synthesis combines information from multiple sources, identifying connections, patterns and differences.',difficulty:'intermediate'},
           {id:'eng-re-q6',topicId:'eng-reading-evaluation',question:'When comparing texts, what should you compare beyond content?',options:['Only the length of each text','The writers\' methods: language, structure, tone and effects','Only the titles','The publication dates'],correctAnswer:1,explanation:'Strong comparison examines HOW writers convey ideas (methods) not just WHAT they say (content). This includes language choices, structure, tone and effects.',difficulty:'intermediate'},
           {id:'eng-re-q7',topicId:'eng-reading-evaluation',question:'Which comparative connective effectively links ideas across two texts?',options:['And then','Similarly, both writers use... However, Writer B differs by...','The end','Also'],correctAnswer:1,explanation:'Comparative connectives like "similarly," "in contrast," "however," and "whereas" explicitly link ideas between texts, creating a cohesive comparative argument.',difficulty:'intermediate'},
           {id:'eng-re-q8',topicId:'eng-reading-evaluation',question:'Why might two writers approach the same topic differently?',options:['One is better than the other','Differences in context: time period, audience, purpose and personal experience','They didn\'t read each other\'s work','There is no reason'],correctAnswer:1,explanation:'Context shapes writing. A Victorian writer and a modern journalist may use different language, tone and conventions even on the same topic, influenced by their era, audience and purpose.',difficulty:'intermediate'},
           {id:'eng-re-q9',topicId:'eng-reading-evaluation',question:'In an evaluation question, can you disagree with the given statement?',options:['No, you must always agree','Yes, as long as you support your view with evidence and analysis','Only partially','You should avoid taking a position'],correctAnswer:1,explanation:'You can agree, disagree, or partially agree. What matters is that your position is clear, consistent and supported by evidence and analysis throughout.',difficulty:'foundation'},
           {id:'eng-re-q10',topicId:'eng-reading-evaluation',question:'What makes a strong evaluation different from a weak one?',options:['Length','A strong evaluation analyses specific methods and their effects; a weak one makes vague claims without evidence','Using more quotes','Writing in the first person'],correctAnswer:1,explanation:'Strong evaluation is specific and analytical, linking writer\'s methods to effects on the reader and supporting every claim with evidence. Weak evaluation makes general statements without textual support.',difficulty:'higher'},
           {id:'eng-re-q11',topicId:'eng-reading-evaluation',question:'When synthesising two texts about poverty, which approach is best?',options:['Summarise Text A, then summarise Text B separately','Draw together both texts, comparing how each writer presents the experience of poverty','Only discuss Text A','Ignore both texts and write your own opinion'],correctAnswer:1,explanation:'Synthesis requires drawing texts together, identifying connections and differences. Discussing them separately is summary, not synthesis.',difficulty:'intermediate'},
           {id:'eng-re-q12',topicId:'eng-reading-evaluation',question:'What role does context play when comparing a 19th-century and a modern text?',options:['No role','It explains differences in language, conventions and attitudes between the two time periods','It only matters for the older text','Context is irrelevant to English Literature'],correctAnswer:1,explanation:'Context helps explain why writers use different language, hold different attitudes, and follow different conventions. Understanding context enables deeper, more nuanced comparison.',difficulty:'higher'},
           {id:'eng-re-q13',topicId:'eng-reading-evaluation',question:'Which opening best sustains an evaluative argument?',options:['"I will now discuss the statement"','"The writer creates a powerful sense of danger from the very opening line, using violent imagery that escalates throughout"','"This is a good text"','"The statement is about danger"'],correctAnswer:1,explanation:'The second option immediately presents a clear evaluative position with reference to specific methods (violent imagery) and structure (escalation), demonstrating confident analytical writing.',difficulty:'higher'},
           {id:'eng-re-q14',topicId:'eng-reading-evaluation',question:'How should you use evidence when evaluating a text?',options:['Use as many quotes as possible','Select specific, relevant quotations and analyse the effect of particular word choices within them','Avoid using quotations','Only use quotations from the first paragraph'],correctAnswer:1,explanation:'Evidence should be carefully selected, relevant to your argument, and analysed in detail. Focus on the effect of specific words rather than quoting long passages.',difficulty:'intermediate'},
           {id:'eng-re-q15',topicId:'eng-reading-evaluation',question:'A student writes: "Both texts are about war. Text A talks about soldiers. Text B also talks about soldiers." What is wrong?',options:['Nothing, this is good synthesis','This is summary, not synthesis — it lacks comparison of methods and does not draw the texts together analytically','It is too short','It uses incorrect grammar'],correctAnswer:1,explanation:'This is simple summary, not synthesis. Synthesis requires drawing texts together, comparing methods and effects, not just identifying shared content.',difficulty:'intermediate'}]),
      ],
    },
  ],
  diagnosticQuestions: [
    {id:'eng-diag-01',topicId:'eng-lang1-reading',question:'What does Paper 1 Q3 ask you to analyse?',options:['The writer\'s use of metaphor','How the writer has structured the text to interest the reader','The accuracy of the writer\'s spelling','The historical context of the text'],correctAnswer:1,explanation:'Paper 1 Q3 specifically asks about structure: how the text is organised, how the focus shifts, and how the writer uses the beginning, middle and ending to engage the reader.',difficulty:'intermediate'},
    {id:'eng-diag-02',topicId:'eng-lang1-writing',question:'How many marks are awarded for technical accuracy in Paper 1 Section B?',options:['10 marks','24 marks','16 marks','40 marks'],correctAnswer:2,explanation:'Paper 1 Section B awards 24 marks for content and organisation and 16 marks for technical accuracy (spelling, punctuation and grammar), totalling 40 marks.',difficulty:'intermediate'},
    {id:'eng-diag-03',topicId:'eng-lang2-reading',question:'Paper 2 reading section includes texts from which time periods?',options:['Only 21st-century texts','One 19th-century and one 20th or 21st-century text','Only 19th-century texts','Texts from any period in history'],correctAnswer:1,explanation:'AQA Paper 2 presents two linked non-fiction texts: one from the 19th century and one from the 20th or 21st century, allowing comparison across different time periods.',difficulty:'intermediate'},
    {id:'eng-diag-04',topicId:'eng-lang2-writing',question:'Which writing form would require a headline and potentially subheadings?',options:['A formal letter','A speech','A newspaper or magazine article','An essay'],correctAnswer:2,explanation:'An article for a newspaper or magazine requires a headline to capture attention and may use subheadings to organise the content. Letters need addresses, speeches need direct address, and essays use a formal structure.',difficulty:'intermediate'},
    {id:'eng-diag-05',topicId:'eng-macbeth-themes',question:'Which theme is established from the very opening of Macbeth?',options:['Romantic love','Appearance versus reality','Comedy and humour','The importance of education'],correctAnswer:1,explanation:'The Witches establish the theme of appearance vs reality from the opening scene with their paradox. This theme runs throughout the play as characters disguise their true intentions.',difficulty:'intermediate'},
    {id:'eng-diag-06',topicId:'eng-macbeth-characters',question:'What term describes Banquo\'s dramatic function in relation to Macbeth?',options:['Protagonist','Antagonist','Foil','Narrator'],correctAnswer:2,explanation:'Banquo is a dramatic foil to Macbeth. He receives the same prophecy but resists the temptation to act immorally, highlighting Macbeth\'s moral failure by contrast.',difficulty:'higher'},
    {id:'eng-diag-07',topicId:'eng-19c-context',question:'What does the Victorian concept of the "Angel in the House" refer to?',options:['A ghost story about a haunted house','The idealised image of women as pure, submissive homemakers','A type of Gothic architecture','An angelic character in a Dickens novel'],correctAnswer:1,explanation:'The "Angel in the House" was the Victorian ideal of femininity: women were expected to be pure, pious, submissive and devoted to home and family. Many 19th-century novels explore characters who are constrained by or challenge this ideal.',difficulty:'intermediate'},
    {id:'eng-diag-08',topicId:'eng-19c-analysis',question:'A Victorian novelist uses a storm scene immediately after a character commits a crime. What technique is this?',options:['Alliteration','Pathetic fallacy','Onomatopoeia','Irony'],correctAnswer:1,explanation:'Pathetic fallacy is the technique of using weather or natural environment to reflect emotional states or moral atmosphere. The storm mirrors the moral turmoil following the character\'s crime.',difficulty:'intermediate'},
    {id:'eng-diag-09',topicId:'eng-poetry-power',question:'What is caesura in poetry?',options:['A type of rhyme scheme','A pause in the middle of a line, usually created by punctuation','The final line of a poem','A poem with no structure'],correctAnswer:1,explanation:'Caesura is a deliberate pause within a line of poetry, typically created by punctuation such as a full stop, comma or dash. It can create a sense of interruption, hesitation or emphasis.',difficulty:'intermediate'},
    {id:'eng-diag-10',topicId:'eng-poetry-comparison',question:'What is the most effective way to structure a poetry comparison?',options:['Write about each poem completely separately','Compare specific aspects of both poems within each paragraph','Only write about the named poem','List every technique in both poems'],correctAnswer:1,explanation:'An integrated comparison that addresses both poems within each paragraph is most effective. Use comparative connectives to move between the texts and compare specific methods and themes.',difficulty:'higher'},
    {id:'eng-diag-11',topicId:'eng-modern-themes',question:'What does "authorial intent" mean?',options:['The author\'s biography','What the writer is deliberately trying to convey or suggest to the reader about society, morality or human nature','The date the text was published','How many copies the book sold'],correctAnswer:1,explanation:'Authorial intent refers to the writer\'s purpose: what they are trying to suggest, convey or argue through their text. Demonstrating awareness of this in essays shows higher-level analysis.',difficulty:'intermediate'},
    {id:'eng-diag-12',topicId:'eng-writing-techniques',question:'Which of the following is an example of a rhetorical question?',options:['"What time does the shop close?"','"Can we really stand by and watch our planet burn?"','"Where did you put my keys?"','"How many students passed the exam?"'],correctAnswer:1,explanation:'A rhetorical question is asked for persuasive effect rather than to receive an answer. It prompts the audience to reflect and implicitly agree with the speaker\'s position.',difficulty:'intermediate'},
    {id:'eng-diag-13',topicId:'eng-writing-accuracy',question:'Which sentence correctly uses an apostrophe for possession?',options:['"The cat\'s were sleeping in the garden."','"The teacher\'s desk was covered in papers."','"It\'s tail was fluffy and long."','"The student\'s were revising for their exam\'s."'],correctAnswer:1,explanation:'"The teacher\'s desk" correctly uses the apostrophe to show the desk belongs to the teacher. The other options either use apostrophes for plurals (incorrect) or confuse "it\'s" (it is) with "its" (possession).',difficulty:'intermediate'},
    {id:'eng-diag-14',topicId:'eng-reading-analysis',question:'What does PEEL stand for in analytical writing?',options:['Practice, Evaluate, Examine, Learn','Point, Evidence, Explain, Link','Plan, Execute, Edit, List','Predict, Explore, Engage, Listen'],correctAnswer:1,explanation:'PEEL stands for Point (make a clear analytical statement), Evidence (support with a quotation), Explain (analyse the effect of specific words), Link (connect back to the question or forward to the next point).',difficulty:'intermediate'},
    {id:'eng-diag-15',topicId:'eng-reading-evaluation',question:'What is the difference between summarising two texts and synthesising them?',options:['There is no difference','Summarising deals with one text; synthesis draws information from both texts to identify connections and comparisons','Synthesis is shorter than a summary','Summarising is more analytical than synthesis'],correctAnswer:1,explanation:'Summary restates what individual texts say. Synthesis is more sophisticated: it draws information together from both texts to identify patterns, connections, and differences, building a richer comparative understanding.',difficulty:'higher'},
  ],
};
